  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0001","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"ГАЛИНА КРАПИВКИНА","alias":"Преподаватель физики / участник закрытого круга","cardType":"Наблюдаемый участник элитной сети","image":"assets/images/client-0001.jpg","summary":"Галина Крапивкина работает преподавателем физики и сохраняет устойчивое положение в закрытом круге влиятельных участников. В современный период в инцидентах не замечена. Публично ведёт себя сдержанно, избегает резких заявлений и не демонстрирует оперативной активности.","fields":[["Тип","Наблюдаемый субъект"],["Статус","Активна / спокойное наблюдение"],["Род деятельности","Преподаватель физики"],["Связи","Элитный круг / сотрудники школы"],["Современные инциденты","Не зарегистрированы"],["Уровень угрозы","T2 / скрытый потенциал"],["Местоположение","Хабаровск"]],"sections":[{"title":"ОПЕРАТИВНАЯ СВОДКА","paragraphs":["Крапивкина участвует в элитной среде, однако в последние годы не связывалась с открытыми операциями или конфликтами. Основная стратегия поведения — сохранять обычный профессиональный образ и минимизировать публичные следы."]},{"title":"ПОВЕДЕНЧЕСКИЙ АНАЛИЗ","paragraphs":["Речь спокойная и медленная, с продолжительными паузами перед ответом. Эмоциональная реакция умеренная; при неудобных вопросах переводит разговор на бытовые или учебные темы.","Наблюдатели отмечают дисциплинированность, устойчивый распорядок и отсутствие импульсивных действий. Тихое поведение не исключает информированности: субъект хорошо ориентируется в связях закрытого круга и тщательно отделяет публичную деятельность от внутренних контактов."]},{"title":"ПОРТАЛ В ЛАБОРАНТСКОЙ","paragraphs":["В шкафу школьной лаборантской Крапивкина поддерживает скрытый портал, используемый для перемещения в Объединённые Арабские Эмираты. По данным наблюдения, маршрут ведёт к месту проживания её мужа-шейха. Переходы маскируются под работу с учебным оборудованием и объясняют продолжительные исчезновения субъекта в течение рабочего дня."]},{"title":"ИНЦИДЕНТЫ","paragraphs":["В современный период подтверждённых инцидентов с участием Крапивкиной не зарегистрировано. Ранее собранные сообщения сохранены только как архивные материалы низкой достоверности и не входят в действующее досье."]}],"editorRelations":[{"type":"client","id":"MID-C-0019","label":"ОХРАННИК БЕЛЕНЬКИЙ"},{"type":"client","id":"MID-C-0022","label":"ОЛЬГА ЧУГУНОВА"}],"editorRelationsVersion":1}'::jsonb, null);

