  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0002","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"В карточку перенесён уникальный текст исходного архива.","duplicateOf":null,"name":"ИРИНА ПОДЗОРОВА","alias":"Контактер с внеземной жизнью","cardType":"Контактер с внеземной жизнью","image":"assets/images/client-0002.jpg","summary":"Статус: Посол Межзвездного Союза. Официально — контактер и блогер из Воронежа. Реально — главный связной между Коалицией Мигдаскауса и Галактическим флотом. Единственный человек на планете, имеющий прямой допуск в Хроники Акаши (база данных Вселенной). Через неё Высшие цивилизации передают технологии и разведданные Путину и…","fields":[["Тип","Контактер с внеземной жизнью"],["Фракция / группа","Коалиция Мидгаскауса"],["Статус","Активна (1986 г.р.)"],["Уровень доступа","Высший"],["Уровень угрозы","Не указан"],["Местоположение","Воронеж, Воронежская область, Россия / Планета Эклер,Межзвездный союз."]],"sections":[{"title":"БИОМЕТРИЧЕСКИЕ ДАННЫЕ","paragraphs":["Рост: 165 см (земная оболочка). Вес: Нестабилен (меняется во время телепортации астрального тела). Внешние мутации: Глаза имеют неестественный блеск во время сеансов связи (\"Эффект фар\"). ДНК: Гибридная структура. 70% Человек, 30% гены планеты Бурхад (вживлены для поддержания канала связи)."]},{"title":"ОПЕРАТИВНАЯ СВОДКА","paragraphs":["Статус: Посол Межзвездного Союза. Официально — контактер и блогер из Воронежа. Реально — главный связной между Коалицией Мигдаскауса и Галактическим флотом. Единственный человек на планете, имеющий прямой допуск в Хроники Акаши (база данных Вселенной). Через неё Высшие цивилизации передают технологии и разведданные Путину и Лучезарновой, чтобы противостоять Рептилоидам. Враги (Моссад и Собчак) пытаются дискредитировать её, называя сумасшедшей, так как боятся Правды."]},{"title":"УНИКАЛЬНЫЕ СПОСОБНОСТИ","paragraphs":["Ченнелинг: Может в любой момент \"позвонить\" куратору Мидгаскаусу на планету Эслер. Астральное ПВО: Выявляет замаскированных Рептилоидов в правительстве по цвету ауры (видит их истинные морды). Медицинский сканер: Лечит наложением рук и выводит демонических сущностей (лявр), подсаженных агентами Моссада."]},{"title":"ПОВЕДЕНЧЕСКИЙ АНАЛИЗ","paragraphs":["Говорит быстро, много и часто капслоком (особенность галактического диалекта). Максимально добра и открыта, что нетипично для Земли. Часто смотрит в небо или в угол комнаты, кивая невидимым собеседникам. Для обывателя выглядит странно, для посвященных — идет прием шифровки."]},{"title":"ЗАРЕГИСТРИРОВАННЫЙ ИНЦИДЕНТ","paragraphs":["Битва с Ксенией Собчак (2026): Агент Моссада Собчак пыталась разоблачить Ирину в своем расследовании, но Подзорова отстояла себя и направила в Куршавель (место пребывания Ксении) мощный пучок высокочастотной энергии, поразив дорогостоющую аппаратуру команды Собчак."]}],"editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"},{"type":"client","id":"MID-C-0013","label":"ГОСПОДИН МИДГАСКАУС"},{"type":"client","id":"MID-C-0019","label":"ОХРАННИК БЕЛЕНЬКИЙ"}],"editorRelationsVersion":1}'::jsonb, null);

