  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0003","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"В карточку перенесён уникальный текст исходного архива.","duplicateOf":null,"name":"КОМАР МУТАНТ","alias":"Мутированное существо","cardType":"Мутированное существо","image":"assets/images/client-0003.jpg","summary":"Объект «Комар» — результат адаптации человека к условиям повышенной токсичности Андреевки. Ведет ночной образ жизни. Питается не кровью (как ошибочно думают дачники), а энергетическим вампиризмом и остатками спиртосодержащих жидкостей, забытых на лавочках и пляжах Андреевки. Издает характерный высокочастотный звук…","fields":[["Тип","Мутированное существо"],["Фракция / группа","Андреевская семья"],["Статус","Активен, мутирует"],["Уровень доступа","Нет"],["Уровень угрозы","Не указан"],["Местоположение","Болота за магазином «Бристоль», теплотрассы. Андреевка."]],"sections":[{"title":"БИОМЕТРИЧЕСКИЕ ДАННЫЕ","paragraphs":["Рост: 165 см (в холке). Вес: 42 кг (очень легкий скелет). Внешние мутации: Конечности неестественно удлинены и истощены. Нос вытянут. Кожа имеет серовато-землистый оттенок с хитиновым блеском на локтях. Глаза выпуклые, фасеточного типа (видит на 360 градусов, зрение помогает в охоте)."]},{"title":"ОПЕРАТИВНАЯ СВОДКА","paragraphs":["Объект «Комар» — результат адаптации человека к условиям повышенной токсичности Андреевки. Ведет ночной образ жизни. Питается не кровью (как ошибочно думают дачники), а энергетическим вампиризмом и остатками спиртосодержащих жидкостей, забытых на лавочках и пляжах Андреевки. Издает характерный высокочастотный звук (писк/зудение) не горлом, а трением коленных суставов друг о друга при ходьбе."]},{"title":"УНИКАЛЬНЫЕ СПОСОБНОСТИ","paragraphs":["Сверхзвуковая скорость: Способен переместиться от мусорки до ларька с шаурмой за 0.02 секунды, если почует запах майонеза. Невидимость: В состоянии алкогольного опьянения становится прозрачным для камер видеонаблюдения и полиции. Токсичный укус: Укус не смертелен, но вызывает у жертвы непреодолимое желание слушать Лободу и сидеть на корточках в течение 3-х дней (вирус «Андреевской тоски»)."]},{"title":"ПОВЕДЕНЧЕСКИЙ АНАЛИЗ","paragraphs":["Агрессии не проявляет, если не махать руками перед лицом. Обладает коллективным разумом с другими мутантами подобного вида. Если ударить Комара на одном конце деревни, мутант на другом конце сразу почувствует боль."]},{"title":"ЗАРЕГИСТРИРОВАННЫЙ ИНЦИДЕНТ","paragraphs":["Летом 2023 года пытался «присосаться» к трансформаторной будке, приняв гул электричества за брачный зов самки. Обесточил половину района. Выжил, стал светиться в темноте фосфорным светом."]}],"editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"}],"editorRelationsVersion":1}'::jsonb, null);

