  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0004","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"В карточку перенесён уникальный текст исходного архива.","duplicateOf":null,"name":"НАСТЯ КАБАЦКАЯ","alias":"Блогер, модель, убита Анной","cardType":"Блогер, модель, убита Анной","image":"assets/images/client-0004.jpg","summary":"Кодовое имя: Агент \"Настенька\". Официально — молодая жена Александра Кабацкого, популярный блогер. Вела гламурный образ жизни, постила сторис с путешествиями по Африке. В действительности являлась проектом контрразведки. Под видом глупенькой блогерши Настя внедрялась в доверие к \"золотой молодежи\", хоккеистам и детям…","fields":[["Тип","Блогер, модель, убита Анной"],["Фракция / группа","Мученики"],["Статус","Убита"],["Уровень доступа","Нет"],["Уровень угрозы","Не указан"],["Местоположение","Хабаровск, Хабаровский край, Россия / Африка"]],"sections":[{"title":"БИОМЕТРИЧЕСКИЕ ДАННЫЕ","paragraphs":["Возраст: 19 лет (на момент гибели). Внешность: Идеальная (слишком идеальная). Кожа без пор, большие выразительные глаза. ДНК: Не найдено. Тело исчезло после \"убийства\"."]},{"title":"ОПЕРАТИВНАЯ СВОДКА","paragraphs":["Кодовое имя: Агент \"Настенька\". Официально — молодая жена Александра Кабацкого, популярный блогер. Вела гламурный образ жизни, постила сторис с путешествиями по Африке. В действительности являлась проектом контрразведки. Под видом глупенькой блогерши Настя внедрялась в доверие к \"золотой молодежи\", хоккеистам и детям чиновников. Через соцсети она собирала компромат на агентов влияния Моссада. Есть версия, что Настя не была человеком. Возможно, это Биоробот нового поколения (Модель Kabanastya33), созданный Кабацким в лаборатории для прикрытия и сбора данных."]},{"title":"УНИКАЛЬНЫЕ СПОСОБНОСТИ","paragraphs":["Могла развести любого на откровенный разговор за 5 минут (Изотов*). Ее посты в телеграмм-канале (с 67 подписчиками) создавались с учетом строгого ритмокодирования (контроль над людьми). Проводила обряды с куклами Вуду. Режим \"Берсерк\": В критической ситуации могла отключить эмпатию и действовать как машина-убийца."]},{"title":"ПОВЕДЕНЧЕСКИЙ АНАЛИЗ","paragraphs":["Абсолютная сингулярность с мужем. На публике играла роль \"глупой настюшки\"."]},{"title":"ОБСТОЯТЕЛЬСТВА ГИБЕЛИ (АВГУСТ 2025)","paragraphs":["Заказчик: Тамара Эйдельман. Поняла, что Настя опасна. Исполнитель: Агент Анка (Анна Киселева) — анимешница. Место: Владивосток, Приморский край, Россия. Анка заманила Настеньку в квартиру, после чего зверски расправилась с ней с помощью подручных средтсв. Голову Насти насадила на палку и оставила в шкафу. Оставшаяся часть тела Насти не была найдена. Кабацкий взял под личный контроль расследование убийства. Исполнителя убийства нашли быстро. Анна Кисилева была арестована. Осенью 2025 приговорена к пожизненному заключению."]}],"editorRelations":[],"editorRelationsVersion":1}'::jsonb, null);

