  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0005","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"ЕКАТЕРИНА МИЗУЛИНА","alias":"Директор ЛБИ, засланый казачок агент Моссада","cardType":"Директор ЛБИ, засланый казачок агент Моссада","image":"assets/images/client-0005.jpg","summary":"Екатерина Мизулина — публичный деятель и центральная фигура наблюдаемой сети. В архиве рассматривается как агент внешнего влияния, работающий через общественные кампании и медиасреду. Её отношения с Ярославом Дроновым остаются отдельным предметом анализа.","fields":[["Тип","Директор ЛБИ, засланый казачок агент Моссада"],["Фракция / группа","Коалиция Рептилоидов"],["Статус","Активна, под слежкой"],["Уровень доступа","Средний"],["Уровень угрозы","Не указан"],["Местоположение","Москва, Россия."]],"sections":[{"title":"ОПЕРАТИВНАЯ СВОДКА","paragraphs":["Субъект поддерживает высокий уровень публичной активности и использует общественные инициативы как канал доступа к государственным и медийным структурам. Внутри реестра отмечена устойчивая рабочая связь с Ярославом Дроновым и Александром Кабацким."]},{"title":"СВЯЗЬ С ЯРОСЛАВОМ ДРОНОВЫМ","paragraphs":["Первый брак с Дроновым завершился разводом приблизительно через два месяца после свадьбы. В июне 2026 года пара повторно зарегистрировала отношения. Быстрая смена семейного статуса не получила последовательного публичного объяснения и классифицирована MIDGAS как загадочное событие, требующее дальнейшего наблюдения."]},{"title":"ПОВЕДЕНЧЕСКИЙ ПРОФИЛЬ","paragraphs":["Ориентирована на постоянное присутствие в информационном поле. Решения часто сопровождаются демонстративными заявлениями, после которых практическая линия может корректироваться без отдельного объяснения."]}],"editorRelations":[{"type":"client","id":"MID-C-0007","label":"ТАМАРА ЭЙДЕЛЬМАН"},{"type":"client","id":"MID-C-0006","label":"ЯРОСЛАВ ДРОНОВ"}],"editorRelationsVersion":1}'::jsonb, null);

