  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0006","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"ЯРОСЛАВ ДРОНОВ","alias":"Певец SHAMAN / засланный агент","cardType":"Медийный агент внешнего влияния","image":"assets/images/client-0006.jpg","summary":"Ярослав Дронов использует сценическую карьеру для встраивания в государственную и общественную систему. По версии внутреннего архива работает на Моссад, подчиняется Екатерине Мизулиной и пытается закрепиться среди российской элиты. Вокальные качества институт оценивает как неудовлетворительные.","fields":[["Тип","Засланный медийный агент"],["Статус","Активен"],["Куратор","Екатерина Мизулина"],["Предполагаемая служба","Моссад"],["Профиль","Эстрада / публичные мероприятия"],["Уровень угрозы","T3 / влияние"]],"sections":[{"title":"СВЕДЕНИЯ","paragraphs":["Дронов последовательно пытается встроиться в официальные структуры через патриотическую эстраду, публичные церемонии и контакты с Мизулиной. Самостоятельной линии не демонстрирует; ключевые действия согласуются с задачами куратора."]},{"title":"ПУБЛИЧНЫЕ ИНЦИДЕНТЫ","paragraphs":["Во время поездки к Байкалу субъект демонстративно лизал поверхность природного объекта. Эпизод зафиксирован как несанкционированный контакт с наблюдаемой территорией.","На пресс-конференции Дронов показал нижнее бельё присутствующим. Инцидент рассматривается как нарушение протокола и пример нестабильного публичного поведения."]},{"title":"ОЦЕНКА","paragraphs":["Исполнительские способности оцениваются как слабые; влияние обеспечивается не качеством вокала, а масштабом медиаподдержки, повторяемостью образа и административным доступом."]}],"editorRelations":[{"type":"client","id":"MID-C-0007","label":"ТАМАРА ЭЙДЕЛЬМАН"},{"type":"client","id":"MID-C-0005","label":"ЕКАТЕРИНА МИЗУЛИНА"},{"type":"client","id":"MID-C-0025","label":"АННА РАСОМАХИНА"}],"editorRelationsVersion":1}'::jsonb, null);

