  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0007","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"ТАМАРА ЭЙДЕЛЬМАН","alias":"Историк / координатор внешней сети","cardType":"Медийный координатор и вербовщик","image":"assets/images/client-0007.jpg","summary":"Тамара Эйдельман — историк и публичный лектор, которую внутренний архив связывает с координацией сети агентов влияния. Основные направления наблюдения: работа с исторической повесткой, контакты с Мизулиной, Дроновым и Анной Кисилевой, а также предполагаемое участие в постановке локальных задач.","fields":[["Тип","Координатор внешнего влияния"],["Статус","Активна"],["Публичная роль","Историк / лектор"],["Связанные клиенты","MID-C-0005, MID-C-0006, MID-C-0016"],["Уровень угрозы","T4 / координационный"]],"sections":[{"title":"СВЕДЕНИЯ","paragraphs":["Публичная деятельность Эйдельман строится вокруг исторических лекций и комментариев. Внутреннее расследование рассматривает эту работу как удобное прикрытие для формирования нужных интерпретаций событий и отбора лояльных исполнителей."]},{"title":"СЕТЕВЫЕ СВЯЗИ","paragraphs":["Зафиксированы устойчивые связи с Мизулиной и Дроновым. Отдельный эпизод — предполагаемая передача Анне Кисилевой задания против Анастасии Кабацкой летом 2025 года. Прямой документальный канал передачи пока не обнаружен, но последовательность контактов включена в дело."]},{"title":"ПОВЕДЕНЧЕСКИЙ АНАЛИЗ","paragraphs":["Уверенно работает с аудиторией, предпочитает длинные объяснения и редко отвечает на обвинения напрямую. В конфликтной ситуации переводит обсуждение из оперативной плоскости в историческую или моральную."]},{"title":"ЭПИЗОД С ЛОШАДЬЮ","paragraphs":["Во время верховой езды Эйдельман упала с лошади. Архивные кадры происшествия стали предметом отдельного анализа: на нескольких повреждённых фрагментах наблюдатели отметили нехарактерное продолжение силуэта, интерпретированное как хвост. Исходное видео вскоре исчезло из открытого доступа; сохранившиеся копии находятся в архиве Кабацкого."]}],"editorRelations":[{"type":"client","id":"MID-C-0005","label":"ЕКАТЕРИНА МИЗУЛИНА"},{"type":"client","id":"MID-C-0006","label":"ЯРОСЛАВ ДРОНОВ"},{"type":"client","id":"MID-C-0016","label":"АННА КИСИЛЕВА"}],"editorRelationsVersion":1}'::jsonb, null);

