  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0008","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"ЕВДОКИЯ ЛУЧЕЗАРНОВА","alias":"Евдокия Лучезарнова / руководитель ритмологического направления","cardType":"Исследователь и идеолог ритмологической школы","image":"assets/images/client-0009.jpg","summary":"Евдокия Лучезарнова — автор ритмологического направления и участник союзной сети MIDGAS. Институт изучает её методики как систему текстовых, временных и поведенческих практик, используемых для координации участников и интерпретации событий.","fields":[["Тип","Предводитель Гипербореи, спасительница мира, ритмолог"],["Фракция / группа","Коалиция Мидгаскауса"],["Статус","Активна"],["Уровень доступа","Максимальный"],["Уровень угрозы","Не указан"],["Местоположение","Миас, Челябинская область, Россия."]],"sections":[{"title":"ПРОФИЛЬ","paragraphs":["Лучезарнова ведёт авторскую школу, выпускает тексты и формирует понятийный аппарат, связанный с ритмами, временем и управлением вниманием. В архиве отделены публичные заявления, практические методики и неподтверждённые свидетельства последователей."]},{"title":"РОЛЬ В СЕТИ","paragraphs":["Поддерживает контакты с Подзоровой, Кабацким, Крапивкиной и Мидгаскаусом. Выступает консультантом по смысловой структуре сообщений и долгосрочной координации союзных групп."]},{"title":"ОЦЕНКА MIDGAS","paragraphs":["Субъект не рассматривается как непосредственная физическая угроза. Основное влияние — организационное и идеологическое. Материалы требуют раздельного анализа без смешения авторской терминологии с измеряемыми данными."]}],"editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"},{"type":"client","id":"MID-C-0019","label":"ОХРАННИК БЕЛЕНЬКИЙ"}],"editorRelationsVersion":1}'::jsonb, null);

