  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0009","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"АЛЕКСАНДР КАБАЦКИЙ","alias":"Каба / оперативный координатор MIDGAS","cardType":"Оперативный агент и координатор","image":"assets/images/client-0010.jpg","summary":"Александр Кабацкий — оперативный координатор союзной сети. Работает рядом с Екатериной Мизулиной, контролирует доступ к её окружению и ведёт собственные агентурные проекты. Курировал Киблюху, мужа Анны Кисилевой и расследование убийства Анастасии Кабацкой.","fields":[["Тип","Оперативный координатор"],["Статус","Активен / союзник"],["Кодовое имя","Каба"],["Организация","THE MIDGAS"],["Зона работы","Россия / международные маршруты"],["Уровень доступа","D5 / максимальный"]],"sections":[{"title":"СЛУЖЕБНЫЙ ПРОФИЛЬ","paragraphs":["Кабацкий отвечает за сбор сведений, внедрение технических средств наблюдения и управление доверенными исполнителями. Публичная роль используется как прикрытие для длительного присутствия рядом с объектами наблюдения."]},{"title":"АГЕНТУРНАЯ СЕТЬ","paragraphs":["К его проектам относятся биоробот Киблюха, внедрённый к Анне Кисилевой, завербованный муж Кисилевой, а также агенты Анна Расомахина и Ольга Кобра. Работа строится через раздельные поручения: исполнители знают только собственный участок операции."]},{"title":"РАССЛЕДОВАНИЕ 2025","paragraphs":["После убийства Анастасии Кабацкой взял расследование под личный контроль. Показания мужа Кисилевой и материалы Киблюхи позволили быстро установить исполнителя и восстановить подготовительную фазу операции."]},{"title":"ОЦЕНКА","paragraphs":["Действует методично, избегает публичного описания операций, предпочитает техническую фиксацию и контроль источников. В союзной структуре обладает высоким уровнем доверия и самостоятельности."]}],"editorRelations":[{"type":"client","id":"MID-C-0012","label":"КИБЛЮХА БИОРОБОТ"},{"type":"client","id":"MID-C-0017","label":"АНДРЕЙ МОЙЩИК"},{"type":"client","id":"MID-C-0019","label":"ОХРАННИК БЕЛЕНЬКИЙ"},{"type":"client","id":"MID-C-0025","label":"АННА РАСОМАХИНА"},{"type":"client","id":"MID-C-0026","label":"ОЛЬГА КОБРА"}],"editorRelationsVersion":1}'::jsonb, null);

