  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0010","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"АНАСТАСИЯ ЕСТАФЬЕВНА","alias":"Школьный сотрудник / мутант Андреевского происхождения","cardType":"Радиационно изменённый школьный сотрудник","image":"assets/images/client-0011.jpg","summary":"Анастасия Естафьевна ранее жила в Андреевке и получила устойчивые мутационные изменения. После переезда работала в школе. Архив связывает её с исчезновением учеников и эпизодом каннибализма в подвальном помещении учебного здания.","fields":[["Тип","Мутант"],["Статус","Наблюдение"],["Происхождение","Андреевка"],["Место работы","Школа"],["Уровень угрозы","T5 / критический"],["Ключевой инцидент","Подвал школы / пропажа учеников"]],"sections":[{"title":"БИОГРАФИЧЕСКАЯ СПРАВКА","paragraphs":["До переезда субъект проживал в зоне Андреевской аномалии. Период проживания совпадает с предполагаемым интенсивным воздействием остаточного загрязнения."]},{"title":"ИНЦИДЕНТ В ШКОЛЕ","paragraphs":["Во время работы в школе была связана с исчезновением нескольких учеников. По материалам внутреннего дела, дети были убиты и съедены в подвальном помещении. Полный объём вещественных доказательств остаётся закрытым."]},{"title":"ПОВЕДЕНИЕ","paragraphs":["В повседневной обстановке сохраняла функциональность и выполняла рабочие обязанности. Опасные реакции проявлялись скрытно, без длительной публичной эскалации."]}],"editorRelations":[],"editorRelationsVersion":1}'::jsonb, null);

