  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0011","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0010","name":"КЕПОЧНИК МУТАНТ","alias":"Кепочник / охранник гаражей на Истомина","cardType":"Радиоактивный агрессивный мутант","image":"assets/images/client-0012.jpg","summary":"Мужчина 1955 года рождения, охраняющий гаражи на улице Истомина. Всегда носит кепку. После облучения в Андреевке переехал в Хабаровск; наблюдаются продолжающиеся мутационные изменения и выраженная агрессия к посторонним.","fields":[["Тип","Мутант"],["Год рождения","1955"],["Статус","Активен / опасен"],["Местоположение","Гаражи на Истомина, Хабаровск"],["Источник облучения","MID-A-0001 / Андреевка"],["Уровень угрозы","T5 / критический"]],"sections":[{"title":"НАБЛЮДЕНИЕ","paragraphs":["Субъект постоянно находится в гаражном массиве, контролирует проходы и агрессивно реагирует на исследовательское оборудование. Кепка является устойчивым элементом внешности и используется как основной визуальный идентификатор."]},{"title":"ИНЦИДЕНТ 2019","paragraphs":["В 2019 году во время обследования гаражей напал на сотрудника MIDGAS с лопатой и пытался нанести смертельные повреждения. Сотруднику удалось покинуть сектор; повторное обследование проводится только группой."]},{"title":"МУТАЦИОННЫЙ СТАТУС","paragraphs":["После проживания в Андреевке отмечены изменения кожи, моторики и поведения. Процесс считается продолжающимся; дистанционный контроль обязателен."]}],"editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"}],"editorRelationsVersion":1}'::jsonb, null);

