  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0012","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"КИБЛЮХА БИОРОБОТ","alias":"Киба / собака-биоробот проекта Кабацкого","cardType":"Разведывательный биоробот","image":"assets/clients/mid-c-0012-kiblyukha-new.webp","summary":"Киблюха — собака-биоробот проекта Александра Кабацкого. Была подменена Анне Кисилевой вместо её настоящей собаки, вела наблюдение и собирала данные совместно с мужем Кисилевой. После завершения операции Кабацкий забрал устройство и вывез его в Китай.","fields":[["Тип","Собака-биоробот"],["Создатель / оператор","Александр Кабацкий"],["Задача","Наблюдение за Анной Кисилевой"],["Связной","MID-C-0017 / Андрей Мойщик"],["Текущий статус","Вывезена в Китай"],["Уровень доступа","D4 / закрытый"]],"sections":[{"title":"ВНЕДРЕНИЕ","paragraphs":["Киблюха была помещена в дом Анны Кисилевой вместо её настоящей собаки. Внешность и поведенческие реакции позволяли устройству не вызывать подозрений в бытовой обстановке."]},{"title":"СБОР ДАННЫХ","paragraphs":["Биоробот фиксировал перемещения, разговоры и контакты Кисилевой. Информация сопоставлялась с наблюдениями её мужа, завербованного Кабацким."]},{"title":"ЗАВЕРШЕНИЕ ОПЕРАЦИИ","paragraphs":["После ареста Кисилевой Кабацкий изъял Киблюху и перевёз её в Китай. Текущее место хранения и техническое состояние закрыты."]}],"imageFit":"cover","cardImage":"assets/clients/mid-c-0012-kiblyukha-new.webp","editorRelations":[{"type":"client","id":"MID-C-0017","label":"АНДРЕЙ МОЙЩИК"},{"type":"client","id":"MID-C-0009","label":"АЛЕКСАНДР КАБАЦКИЙ"},{"type":"client","id":"MID-C-0016","label":"АННА КИСИЛЕВА"}],"editorRelationsVersion":1}'::jsonb, null);

