  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0014","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0009","name":"АШТАР ШЕРАН","alias":"Командующий флотом Галактической Федерации Света","cardType":"Сириусианский адмирал и куратор Земли","image":"assets/images/client-0015.jpg","summary":"Аштар Шеран — представитель цивилизации системы Сириуса B, командующий космическим флотом Галактической Федерации Света. Его родной мир был уничтожен в космической войне около 12 тысяч лет назад; уцелевшая цивилизация продолжила существование на автономных кораблях. В материалах проекта флот размещается примерно в 37–44 астрономических единицах от Солнца.","fields":[["Тип","Внеземной гуманоид"],["Происхождение","Система Сириуса B"],["Должность","Руководитель космического флота"],["Специализация","Военный анализ, политология, межпланетные конфликты"],["Рост","Около 2,5 м"],["Статус","Союзник / куратор Земли"],["Район флота","37–44 а.е. от Солнца"]],"sections":[{"title":"ПРОИСХОЖДЕНИЕ","paragraphs":["Согласно материалам «Кассиопеи», родной мир Аштара был уничтожен во время масштабной космической войны приблизительно 12 тысяч лет назад. Выжившие представители его народа сохранили цивилизацию на больших автономных кораблях и сформировали мобильную систему управления флотом."]},{"title":"СЛУЖЕБНАЯ РОЛЬ","paragraphs":["Аштар описывается как руководитель флота Галактической Федерации Света, военный аналитик, политолог, специалист по межпланетным конфликтам и участник стратегических решений, касающихся Земли. Его задача — защита молодых цивилизаций, дипломатическое сдерживание и предупреждение внешнего вмешательства."]},{"title":"ВНЕШНОСТЬ ПО МАТЕРИАЛАМ ПОДЗОРОВОЙ","paragraphs":["Высокий пожилой гуманоид ростом около 2,5 метра. Вытянутое человеческое лицо, желтоватая кожа, тёмные почти чёрные глаза, небольшой нос и длинные белые волосы, зачёсанные назад. Носит жёлтую форму, напоминающую пластинчатые рыцарские доспехи, и шлем. Говорит спокойным человеческим голосом и, по словам контактёра, знает русский язык."]},{"title":"ХАРАКТЕР И ДОКТРИНА","paragraphs":["Производит впечатление старого, спокойного и строго дисциплинированного адмирала. Любовь трактует как ответственность, самообладание и защиту жизни. Не считается абсолютным пацифистом: силовое вмешательство допустимо для прекращения уничтожения цивилизации, однако приоритет отдан переговорам, наблюдению и предотвращению конфликта."]},{"title":"ОТНОШЕНИЕ К ЗЕМЛЕ","paragraphs":["Не позиционируется как бог или спаситель. Земля должна самостоятельно пройти духовное и социальное взросление; внешние силы могут ограничивать чужое вмешательство и давать рекомендации. Главными препятствиями для вступления человечества в Межзвёздный союз названы войны, ненависть, страх, борьба за власть и паническая реакция на иные цивилизации."]},{"title":"РАСХОЖДЕНИЯ В СООБЩЕНИЯХ","paragraphs":["Различия между сообщениями, приписываемыми Аштару, объясняются возможной подменой источника и влиянием самого контактёра. Переданная информация проходит через память, лексику, настроение и мировоззрение человека, поэтому противоречащие тексты не признаются равнозначными прямыми сообщениями."]}],"editorRelations":[{"type":"client","id":"MID-C-0019","label":"ОХРАННИК БЕЛЕНЬКИЙ"}],"editorRelationsVersion":1}'::jsonb, null);

