  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0016","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0007","name":"АННА КИСИЛЕВА","alias":"Анка / учитель немецкого / агент Моссада","cardType":"Осуждённый агент и исполнитель убийства","image":"assets/images/client-0022.jpg","summary":"Анна Кисилева, 25 лет, родилась в Чегдомыне. Во время учёбы в Германии была завербована Моссадом. После возвращения работала учителем немецкого языка и собирала сведения о Галине Крапивкиной. В августе 2025 года убила Анастасию Кабацкую во Владивостоке; осуждена пожизненно и направлена в колонию «Чёрный дельфин».","fields":[["Тип","Завербованный агент / исполнитель"],["Возраст","25 лет"],["Место рождения","Чегдомын"],["Профессия","Учитель немецкого языка"],["Куратор операции","Тамара Эйдельман"],["Статус","Пожизненное заключение / «Чёрный дельфин»"],["Уровень угрозы","T5 / критический"]],"sections":[{"title":"ВЕРБОВКА И РАБОТА","paragraphs":["Кисилева уехала учиться в Германию, где была завербована агентами Моссада. После возвращения в Россию устроилась преподавателем немецкого языка в ту же школьную среду, где работала Галина Крапивкина, и передавала сведения о ней внешним кураторам."]},{"title":"ЛИЧНЫЙ ПРОФИЛЬ","paragraphs":["Увлекалась аниме, Pokémon и косплеем, участвовала в конкурсах. На позднем этапе наблюдения проявляла дезорганизованное поведение и признаки тяжёлого психического расстройства."]},{"title":"УБИЙСТВО АНАСТАСИИ КАБАЦКОЙ","paragraphs":["Летом 2025 года получила от Тамары Эйдельман задание убить Анастасию Кабацкую. В августе заманила её в квартиру во Владивостоке и убила подручными средствами. Голову жертвы насадила на палку и оставила в шкафу; остальная часть тела не найдена."]},{"title":"РАССЛЕДОВАНИЕ И ПРИГОВОР","paragraphs":["Александр Кабацкий взял расследование под личный контроль. Данные Киблюхи и показания мужа Кисилевой позволили быстро установить исполнителя. Кисилева была арестована, осуждена на пожизненное лишение свободы и отправлена в колонию «Чёрный дельфин»."]}],"editorRelations":[{"type":"client","id":"MID-C-0007","label":"ТАМАРА ЭЙДЕЛЬМАН"},{"type":"client","id":"MID-C-0012","label":"КИБЛЮХА БИОРОБОТ"},{"type":"client","id":"MID-C-0017","label":"АНДРЕЙ МОЙЩИК"}],"editorRelationsVersion":1}'::jsonb, null);

