  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0017","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0008","name":"АНДРЕЙ МОЙЩИК","alias":"Муж Анны Кисилевой / агент Кабацкого","cardType":"Завербованный бытовой источник","image":"assets/images/client-0023.jpg","summary":"Муж Анны Кисилевой был завербован Александром Кабацким и собирал сведения о супруге. Работал на автомойке, позднее дал следствию показания, использованные в деле об убийстве Анастасии Кабацкой. Сейчас проживает во Владивостоке.","fields":[["Тип","Агентурный источник"],["Куратор","Александр Кабацкий"],["Прежняя работа","Автомойка"],["Задача","Наблюдение за Анной Кисилевой"],["Текущий статус","Жив / Владивосток"]],"sections":[{"title":"ВЕРБОВКА","paragraphs":["Кабацкий привлёк субъекта как источник внутри ближайшего окружения Кисилевой. Тот фиксировал поездки, контакты и изменения поведения супруги."]},{"title":"СОВМЕСТНАЯ РАБОТА С КИБЛЮХОЙ","paragraphs":["Наблюдения мужа сопоставлялись с данными собаки-биоробота Киблюхи. Разделение каналов позволило проверить ключевые эпизоды независимо."]},{"title":"ПОКАЗАНИЯ","paragraphs":["После убийства Анастасии Кабацкой передал следствию собранные материалы и дал показания. В настоящее время живёт во Владивостоке; оперативная роль завершена."]}],"editorRelations":[{"type":"client","id":"MID-C-0012","label":"КИБЛЮХА БИОРОБОТ"},{"type":"client","id":"MID-C-0009","label":"АЛЕКСАНДР КАБАЦКИЙ"},{"type":"client","id":"MID-C-0016","label":"АННА КИСИЛЕВА"}],"editorRelationsVersion":1}'::jsonb, null);

