  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0018","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0010","name":"ПОДОРОЖНИЦА ЛЮСИНДА","alias":"Люсинда / участница секты «Бабки Подорожник»","cardType":"Радиационная сектантка полуострова Витязь","image":"assets/clients/mid-c-0018-lucinda-new.webp","summary":"Подорожница Люсинда живёт в кустарниковой зоне полуострова Витязь рядом с Андреевкой. Состоит в секте «Бабки Подорожник», считает растение одновременно защитой от радиации и способом усвоения её энергии.","fields":[["Тип","Сектантка / облучённый субъект"],["Группа","«Бабки Подорожник»"],["Местоположение","Полуостров Витязь"],["Статус","Активна"],["Уровень угрозы","T4 / вооружена"]],"sections":[{"title":"ОБРАЗ ЖИЗНИ","paragraphs":["Постоянного жилья не имеет, перемещается между зарослями и временными укрытиями недалеко от Андреевки. Использует листья подорожника в пище, повязках и защитных ритуалах."]},{"title":"ИНЦИДЕНТ 2021","paragraphs":["В 2021 году на базе «Робинзон» пыталась проникнуть ночью в домик туристов с ножом. Нападение сорвалось, поскольку Люсинда не смогла открыть входную дверь. Пострадавших не было."]},{"title":"ПРОТОКОЛ","paragraphs":["Не приближаться в одиночку. Наличие растений в руках не означает отсутствие холодного оружия."]}],"cardImage":"assets/clients/mid-c-0018-lucinda-new.webp","imageFit":"cover","editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"}],"editorRelationsVersion":1}'::jsonb, null);

