  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0019","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0008","name":"ОХРАННИК БЕЛЕНЬКИЙ","alias":"Телохранитель президента / союзник Кабацкого","cardType":"Сотрудник ФСО и силовой союзник","image":"assets/images/client-0025.jpg","summary":"Беленький — сотрудник ФСО и личный телохранитель Владимира Путина. Ближайший друг Кабацкого, в оперативных материалах характеризуется как «человек-терминатор». Сотрудничает с Крапивкиной, Лучезарновой и Подзоровой; неоднократно предотвращал покушения на представителей российской элиты.","fields":[["Тип","Силовой сотрудник"],["Организация","ФСО"],["Статус","Активен / союзник"],["Куратор","Аштар Шеран"],["Связи","Кабацкий, Крапивкина, Лучезарнова, Подзорова"],["Уровень доступа","D5 / максимальный"]],"sections":[{"title":"СЛУЖЕБНЫЙ ПРОФИЛЬ","paragraphs":["Работает в составе охраны президента и выполняет задачи по выявлению угроз в ближнем контуре. Обладает высокой физической подготовкой и устойчивостью к длительным нагрузкам."]},{"title":"СОЮЗНЫЕ СВЯЗИ","paragraphs":["Поддерживает постоянную связь с Кабацким и привлекается к операциям, где требуется силовое прикрытие. По данным контактной группы, находится под личным кураторством Аштара Шерана."]},{"title":"ОПЕРАЦИИ","paragraphs":["В архиве зафиксировано несколько случаев предотвращения покушений на представителей российской элиты. Подробности закрыты; повторяющийся метод — раннее выявление наблюдателя и бесшумное удаление угрозы из охраняемого периметра."]}],"editorRelations":[{"type":"client","id":"MID-C-0014","label":"АШТАР ШЕРАН"},{"type":"client","id":"MID-C-0009","label":"АЛЕКСАНДР КАБАЦКИЙ"},{"type":"client","id":"MID-C-0001","label":"ГАЛИНА КРАПИВКИНА"},{"type":"client","id":"MID-C-0008","label":"ЕВДОКИЯ ЛУЧЕЗАРНОВА"},{"type":"client","id":"MID-C-0002","label":"ИРИНА ПОДЗОРОВА"}],"editorRelationsVersion":1}'::jsonb, null);

