  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0020","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0010","name":"МУТАНТ ГВАРДЕЙ","alias":"Гвардей / ребёнок, облучённый в Андреевке","cardType":"Стабилизированный андреевский мутант","image":"assets/images/client-0026.jpg","summary":"Мутант Гвардей — ребёнок туристов, получивший сильное облучение во время отдыха в Андреевке. Воздействие изменило внешность и поведение. Для реконструкции лица были установлены титановые пластины. Жив, Хабаровск покинул.","fields":[["Тип","Мутант"],["Источник","Андреевская аномалия"],["Статус","Жив"],["Медицинское вмешательство","Титановые лицевые пластины"],["Текущее местоположение","За пределами Хабаровска"]],"sections":[{"title":"ПРОИСХОЖДЕНИЕ","paragraphs":["Попал в зону воздействия во время семейной туристической поездки в Андреевку. Первые изменения поведения и тканей лица проявились после возвращения."]},{"title":"КОРРЕКЦИЯ","paragraphs":["Разрушенные участки лицевого каркаса были укреплены титановыми пластинами. Операции стабилизировали форму лица, но не устранили нейроповеденческие изменения."]},{"title":"ТЕКУЩИЙ СТАТУС","paragraphs":["Субъект жив и покинул Хабаровск. Точный маршрут не раскрывается; периодически подтверждается дистанционными наблюдениями."]}],"editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"}],"editorRelationsVersion":1}'::jsonb, null);

