  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0021","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0010","name":"МАНЬЯК МУТАНТ","alias":"Маньяк Пятой площадки / хехцирский мутант","cardType":"Разыскиваемый радиоактивный преступник","image":"assets/images/client-0027.jpg","summary":"Мужчина приблизительно 70 лет, скрывающийся в районе Пятой площадки Хабаровска. Ранее ушёл на Хехцир, спасаясь от следствия, и жил в заброшенном бункере — хранилище ядерных отходов. После сильного облучения мутировал; наиболее заметно повреждён нос, который скрывает медицинской маской.","fields":[["Тип","Маньяк / мутант"],["Возраст","Около 70 лет"],["Статус","Разыскивается"],["Источник облучения","Бункер на Хехцире"],["Район активности","Пятая площадка, Хабаровск"],["Уровень угрозы","T5 / критический"]],"sections":[{"title":"ПРОИСХОЖДЕНИЕ МУТАЦИИ","paragraphs":["Скрываясь от следствия, субъект поселился в заброшенном хехцирском бункере, не зная, что объект использовался для хранения ядерных отходов. Длительное проживание вызвало тяжёлые изменения тканей лица и поведения."]},{"title":"МАСКИРОВКА","paragraphs":["После возвращения в город стал постоянно носить медицинскую маску, закрывающую атомные ожоги и деформированный нос. Использует неприметную одежду и меняет маршруты."]},{"title":"НАПАДЕНИЕ / ДЕКАБРЬ 2024","paragraphs":["В декабре 2024 года напал на нескольких людей на Пятой площадке, причинил им тяжёлые повреждения и скрылся. Местонахождение не установлено."]}],"editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"}],"editorRelationsVersion":1}'::jsonb, null);

