  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0022","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0008","name":"ОЛЬГА ЧУГУНОВА","alias":"Учитель истории / агент американской сети","cardType":"Долгосрочный агент внешнего влияния","image":"assets/images/client-0028.jpg","summary":"Ольга Чугунова, 45 лет, родилась в Киргизии, детство провела на Донбассе и Украине. По версии архива была завербована американскими спецслужбами и прошла подготовку в подземных объектах Балаклавы. Сейчас живёт в Хабаровске, работает учителем истории и наблюдает за Галиной Крапивкиной.","fields":[["Тип","Долгосрочный агент"],["Возраст","45 лет"],["Место рождения","Киргизия"],["Подготовка","Балаклава / 1990-е"],["Прикрытие","Учитель истории / муж-военный"],["Текущий объект","Галина Крапивкина"],["Статус","Под наблюдением"]],"sections":[{"title":"БИОГРАФИЯ","paragraphs":["В детстве переехала с семьёй из Киргизии на Донбасс. На Украине попала в поле интереса американских спецслужб; в 1990-е годы была направлена в Балаклаву, где проходила подготовку в подземном комплексе."]},{"title":"ОПЕРАТИВНАЯ ДЕЯТЕЛЬНОСТЬ","paragraphs":["С начала 2000-х перемещалась между российскими регионами, используя семейный статус и службу мужа как прикрытие. География поездок охватывает большинство крупных территориальных центров."]},{"title":"ХАБАРОВСКИЙ ЭТАП","paragraphs":["Устроилась учителем истории в школу, где работает Крапивкина, и ведёт наблюдение за ней. В последнее время попала под активный контроль российских спецслужб и агентурной сети Кабацкого."]}],"editorRelations":[{"type":"client","id":"MID-C-0001","label":"ГАЛИНА КРАПИВКИНА"}],"editorRelationsVersion":1}'::jsonb, null);

