  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0023","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Актуализированное досье внутреннего реестра THE MIDGAS.","duplicateOf":"MID-C-0007","name":"БИОРОБОТ ИРИНУС","alias":"Учитель английского / биороб Иринус","cardType":"Скрытый рептилоидный биоробот","image":"assets/images/client-0029.jpg","summary":"Биороб Иринус работает учителем английского языка в хабаровской школе. Согласно делу, выращена в лабораторной пробирке и действует в интересах рептилоидов. В марте 2018 года на курорте Холдоми превратилась в летательный аппарат с красными глазами и преследовала группу MIDGAS.","fields":[["Тип","Биоробот"],["Публичная роль","Учитель английского языка"],["Оператор","Рептилоидная сеть"],["Статус","Активна / скрыта"],["Ключевой инцидент","Холдоми, март 2018"],["Местоположение","Хабаровск"]],"sections":[{"title":"ПРИКРЫТИЕ","paragraphs":["Продолжает работать учителем, ведёт себя тихо и избегает действий, которые могли бы раскрыть её происхождение. Внешне поддерживает обычный школьный распорядок."]},{"title":"ИНЦИДЕНТ ХОЛДОМИ / 2018","paragraphs":["В марте 2018 года в селе Солнечное Хабаровского края, на территории курорта Холдоми, субъект изменил форму, превратившись в летательный дрон с красными оптическими элементами. Аппарат преследовал полевую команду MIDGAS до её выхода из сектора."]},{"title":"ТЕКУЩАЯ ОЦЕНКА","paragraphs":["Повторных открытых трансформаций не зарегистрировано. Низкая публичная активность рассматривается как сознательная стратегия маскировки."]}],"editorRelations":[],"editorRelationsVersion":1}'::jsonb, null);

