  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0024","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Самостоятельная запись MIDGAS, составленная для клиента MID-C-0024.","duplicateOf":null,"name":"АННА МАЦКЕВИЧ","alias":"Андреевская резонантка","cardType":"Андреевская резонантка","image":"assets/topics/anna-matskevich-record.webp","summary":"Анна Мацкевич — сверхопасный мутировавший клиент и автор собственного TikTok-аккаунта. Во время проживания в Андреевке подвергалась продолжительному воздействию аномального излучения. После выхода из зоны организм клиента стал самостоятельным источником резонансных возмущений.","fields":[["Тип","Андреевская резонантка"],["Фракция / группа","Вне коалиций / Андреевская группа"],["Статус","Активна, под постоянным наблюдением"],["Состояние","Активная постлучевая мутация"],["Уровень доступа","D4 / ограниченный"],["Уровень угрозы","T5 / сверхопасная"],["Местоположение","Не установлено"],["Публичная активность","Ведёт собственный TikTok-аккаунт"],["Связанный объект","MID-A-0001 / Андреевская аномалия"]],"sections":[{"title":"КЛАССИФИКАЦИЯ И БИОМЕТРИЯ","paragraphs":["Исходный биологический тип: человек. Текущая классификация MIDGAS: андреевская резонантка, постлучевая мутация пятого уровня.","Возраст, рост и исходные медицинские показатели не установлены. Представленная фотография используется как базовый визуальный образец. В спокойном состоянии выраженные внешние признаки мутации могут отсутствовать.","Главное изменение затрагивает не форму тела, а характер взаимодействия организма с окружающим пространством. Ткани клиента удерживают остаточное излучение Андреевской аномалии и периодически переводят его в активную фазу."]},{"title":"ИСТОЧНИК МУТАЦИИ","paragraphs":["Во время проживания в Андреевке Анна длительно находилась внутри зоны аномального облучения. Воздействие носило накопительный характер и первоначально не сопровождалось устойчивыми внешними изменениями.","После выхода из Андреевки организм не вернулся к исходному состоянию. Излучение закрепилось в клеточной структуре и сформировало замкнутый резонансный контур. Клиент одновременно является пострадавшей от аномалии и её переносимым продолжением."]},{"title":"ОПЕРАТИВНАЯ СВОДКА","paragraphs":["Анна не проявляет постоянной направленной агрессии. Основная опасность связана с непроизвольными выбросами энергии, интенсивность которых возрастает при стрессе, резком звуке, вспышках света и контакте с другими мутировавшими объектами.","В непосредственной близости от клиента фиксируются нарушения работы камер, экранов, радиосвязи и цифровых датчиков. Поэтому отсутствие записи на оборудовании не считается подтверждением отсутствия клиента в зоне наблюдения.","Несмотря на режим наблюдения, Анна сохраняет публичную активность и ведёт TikTok. Новые публикации рассматриваются как оперативный источник визуальных данных о её состоянии."]},{"title":"УНИКАЛЬНЫЕ СПОСОБНОСТИ","paragraphs":["Резонансное усиление: повышает активность слабых аномальных следов и способна временно переводить неактивные объекты в рабочее состояние.","Электромагнитное подавление: вызывает помехи, повторяющиеся изображения, задержки звука и самопроизвольное включение экранов в радиусе воздействия.","Аномальная память среды: после длительного пребывания клиента помещение может воспроизводить отдельные звуки, силуэты и фрагменты движений с временной задержкой."]},{"title":"ПОВЕДЕНЧЕСКИЙ АНАЛИЗ","paragraphs":["Клиент сохраняет ориентацию, речь и способность к осознанному контакту. Периоды стабильности могут создавать ошибочное впечатление полной безопасности.","Перед энергетическим выбросом обычно наблюдаются фиксация взгляда, снижение реакции на обращение и синхронные помехи на ближайшей технике. Эти признаки рассматриваются как основание для немедленного увеличения дистанции."]},{"title":"ПУБЛИЧНАЯ ЦИФРОВАЯ АКТИВНОСТЬ","paragraphs":["Клиент ведёт собственный аккаунт в TikTok и регулярно появляется перед камерой. Точное имя аккаунта в текущей версии реестра не указано.","Отдел наблюдения сохраняет копии новых публикаций и сравнивает состояние глаз, мимику, освещение и фон кадра. Повтор изображения, выпадение отдельных кадров, задержка звука и появление второго контура лица отмечаются как возможные признаки резонансного выброса.","Публикация нового видео не считается достоверным подтверждением текущего местоположения: цифровые материалы клиента могут загружаться с задержкой или воспроизводиться повторно под воздействием мутации."]},{"title":"ПРОТОКОЛ НАБЛЮДЕНИЯ","paragraphs":["Прямой контакт допускается только сотрудникам с уровнем доступа D4 и выше. Наблюдение проводится с использованием дублирующих аналоговых средств; полностью полагаться на цифровую запись запрещено.","Клиента нельзя доставлять в Андреевку без отдельного решения института. Повторное соединение с исходной зоной может вызвать резкое усиление мутации и расширение радиуса воздействия."]}],"editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"},{"type":"incident","id":"MID-I-0001","label":"ИНЦИДЕНТ СТРАХОМАХА.EXE"}],"editorRelationsVersion":1}'::jsonb, null);

