  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0025","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Новое досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"АННА РАСОМАХИНА","alias":"Агент Кабацкого / внедрение в окружение SHAMAN","cardType":"Агент Кабацкого / внедрение в окружение SHAMAN","image":"assets/clients/mid-c-0025-anna-rasomakhina.webp","summary":"Сведений об Анне Расомахиной немного. Является союзным агентом среднего уровня, выполняет поручения Александра Кабацкого, присутствует в чате Екатерины Мизулиной и канале SHAMAN. Основная задача — войти в круг доверия Дронова и закрепиться в его ближайшем информационном окружении.","fields":[["Тип","Агент среднего уровня"],["Статус","Активна / союзник"],["Куратор","Александр Кабацкий"],["Каналы","Чат Мизулиной / канал SHAMAN"],["Задача","Внедрение в круг доверия SHAMAN"],["Уровень доступа","D3"]],"sections":[{"title":"ОПЕРАТИВНАЯ СВОДКА","paragraphs":["Расомахина выполняет ограниченные поручения Кабацкого и не посвящена в полную структуру операций. Поддерживает образ обычной активной участницы сообществ Мизулиной и Дронова."]},{"title":"ЗАДАЧА","paragraphs":["Постепенно наращивает узнаваемость среди постоянных участников канала SHAMAN, отслеживает внутренние конфликты и пытается получить прямой доступ к Дронову."]},{"title":"ОЦЕНКА","paragraphs":["Наша. Дисциплинирована, работает без демонстративных действий. Объём подтверждённых биографических сведений ограничен; наблюдение продолжается."]}],"editorRelations":[{"type":"client","id":"MID-C-0009","label":"АЛЕКСАНДР КАБАЦКИЙ"},{"type":"client","id":"MID-C-0006","label":"ЯРОСЛАВ ДРОНОВ"},{"type":"client","id":"MID-C-0026","label":"ОЛЬГА КОБРА"}],"editorRelationsVersion":1}'::jsonb, null);

