  insert into public.records (record_type, content, cover_path)
  values ('client', '{"id":"MID-C-0026","kind":"CLIENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Новое досье внутреннего реестра THE MIDGAS.","duplicateOf":null,"name":"ОЛЬГА КОБРА","alias":"Агент Кабацкого / сообщник Расомахиной","cardType":"Агент Кабацкого / сообщник Расомахиной","image":"assets/clients/mid-c-0026-olga-kobra.webp","summary":"Ольга Кобра — союзный агент Кабацкого и сообщник Анны Расомахиной. Присутствует в чате SHAMAN под видом поклонницы. В апреле 2026 года планировала отравить посольство США средством против муравьёв; операция не была доведена до исполнения.","fields":[["Тип","Оперативный агент"],["Статус","Активна / союзник"],["Куратор","Александр Кабацкий"],["Связной","MID-C-0025 / Анна Расомахина"],["Прикрытие","Поклонница SHAMAN"],["Ключевой эпизод","Посольство США / апрель 2026"]],"sections":[{"title":"СВЯЗЬ С РАСОМАХИНОЙ","paragraphs":["Работает в паре с Анной Расомахиной, поддерживает её легенду и помогает закрепляться в сообществах Дронова. Контакты между агентами маскируются под обычное общение поклонниц."]},{"title":"ОПЕРАЦИЯ / АПРЕЛЬ 2026","paragraphs":["Предложила использовать отраву для муравьёв против посольства США. План был остановлен до практической фазы из-за низкой эффективности средства и высокого риска раскрытия."]},{"title":"ТЕКУЩАЯ ЗАДАЧА","paragraphs":["Продолжает находиться в чате SHAMAN, изображая преданную поклонницу. Собирает сведения о модераторах, постоянных участниках и возможных каналах прямой связи."]}],"editorRelations":[{"type":"client","id":"MID-C-0025","label":"АННА РАСОМАХИНА"},{"type":"client","id":"MID-C-0009","label":"АЛЕКСАНДР КАБАЦКИЙ"}],"editorRelationsVersion":1}'::jsonb, null);

