  insert into public.records (record_type, content, cover_path)
  values ('anomaly', '{"id":"MID-A-0001","kind":"ANOMALY","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Полное территориальное досье MIDGAS. Архивная версия.","duplicateOf":null,"name":"АНДРЕЕВСКАЯ АНОМАЛИЯ","alias":"Полуостров Витязь / радиационно-энергетическая зона","cardType":"Территориальная радиационно-энергетическая аномалия","image":"assets/anomalies/mid-a-0001/andreevka-main-cover.webp","summary":"Андреевка публично представлена как приморский курорт. Архив MIDGAS определяет территорию как действующую радиационно-энергетическую зону, образованную ударом XIX века, разрушением тартарских хранилищ и последующим захоронением отходов. Центральная часть частично стабилизировалась, но глубинные участки полуострова Витязь сохраняют активность.","fields":[["Тип","Радиационно-энергетическая территория"],["Статус","Активна / постоянное наблюдение"],["Классификация","A5 / комплексная зона"],["Уровень угрозы","T4 / высокий"],["Уровень доступа","D4 / ограниченный"],["Местоположение","Андреевка, полуостров Витязь, Приморский край"],["Основной маркер","Цезий-137"],["Период возникновения","XIX век"],["Связанная база","Вторая штаб-квартира MIDGAS"],["Цикл наблюдений","Ежегодная экспедиция"]],"sections":[{"title":"ПУБЛИЧНАЯ ВЕРСИЯ: КУРОРТНАЯ АНДРЕЕВКА","paragraphs":["В открытых описаниях Андреевка — приморское село и сезонный курорт: бухты, пляжи, базы отдыха, палаточные лагеря, частный сектор и стихийная торговля. Летом население многократно увеличивается. Внешняя картина складывается из отдыхающих, рынков, лодочных маршрутов и обычных для курортного посёлка бытовых происшествий, включая систематическое употребление алкоголя.","Эта версия не является ложной, но охватывает только верхний слой территории. Курортная инфраструктура занимает наиболее проветриваемую прибрежную полосу, где фон со временем стал менее заметным. Туристический образ выполняет функцию естественной маскировки: поток приезжих делает аномальные симптомы статистически разрозненными и затрудняет долговременное наблюдение за одним человеком."],"media":[{"src":"assets/anomalies/mid-a-0001/andreevka-overview.webp","alt":"Публичный вид Андреевки и бухты","caption":"ОТКРЫТЫЙ СЛОЙ / КУРОРТНАЯ ЗАСТРОЙКА И ПРИБРЕЖНАЯ ПОЛОСА","aspect":"wide"},{"src":"assets/anomalies/mid-a-0001/andreevka-market.webp","alt":"Сезонная торговля в Андреевке","caption":"ОТКРЫТЫЙ СЛОЙ / СЕЗОННАЯ ТОРГОВЛЯ","aspect":"wide"},{"src":"assets/anomalies/mid-a-0001/andreevka-record-cover.webp","alt":"Жилая улица Андреевки после дождя","caption":"ОТКРЫТЫЙ СЛОЙ / ЖИЛАЯ УЛИЦА И НЕУПРАВЛЯЕМЫЙ ПОВЕРХНОСТНЫЙ СТОК","aspect":"wide"}]},{"title":"ТАРТАРСКИЙ ПЕРИОД И ЭНЕРГЕТИЧЕСКИЙ ЦЕНТР","paragraphs":["По материалам института, до разрушения Андреевка служила второй столицей Тартарии и местом пребывания её управленческой и исследовательской элиты. Полуостров был выбран не только из-за защищённой акватории: здесь сходились устойчивые ритмические линии материка и моря, образуя мощный энергетический узел.","Городская система включала подземные залы, хранилища, транспортные коридоры и устройства накопления энергии. Скальные формы полуострова использовались как естественные резонаторы. Сохранившиеся арки и разломы рассматриваются MIDGAS как части разрушенного контура, который продолжает влиять на распределение излучения и поведение живых организмов."],"media":[{"src":"assets/anomalies/mid-a-0001/vityaz-arch.webp","alt":"Скальная арка полуострова Витязь","caption":"ПОЛУОСТРОВ ВИТЯЗЬ / ОСТАТОЧНЫЙ РЕЗОНАНСНЫЙ КОНТУР","aspect":"wide"}]},{"title":"ЯДЕРНЫЙ УДАР XIX ВЕКА","paragraphs":["В XIX веке по энергетическому центру был нанесён самый мощный удар в зарегистрированной истории зоны. Его целью являлись одновременно столица, узел управления и находившиеся под ней ядерные запасы Тартарии. Первичное поражение вызвало вторичное разрушение хранилищ, поэтому фактическая зона воздействия оказалась значительно шире точки удара.","Архив не устанавливает точную мощность события: приборные данные того периода отсутствуют, а позднейшая перепланировка территории уничтожила часть материальных следов. Зафиксирована последовательность — удар, детонация подземных запасов, просадка отдельных полостей и образование долгоживущего радиоактивного контура."]},{"title":"ЛИКВИДАЦИЯ И ПОДЗЕМНЫЕ ХРАНИЛИЩА","paragraphs":["Во время ликвидации последствий войны полуостров использовался как закрытый приёмник радиоактивных материалов. Отходы доставлялись партиями и размещались в уцелевших тартарских полостях, новых бетонных камерах и заглублённых бункерах. Эта практика не устранила первоначальную аномалию, а наложила на неё второй техногенный слой.","Замок Янковского в архивной топологии отмечен как наземный ориентир одного из закрытых секторов. Его бетонный объём и необычная планировка рассматриваются не как самостоятельный источник, а как поздняя маскировочная и служебная оболочка над системой доступа. Входы, показанные на старых схемах, в настоящее время не подтверждены."],"media":[{"src":"assets/anomalies/mid-a-0001/yankovsky-castle.webp","alt":"Замок Янковского","caption":"ЗАМОК ЯНКОВСКОГО / НАЗЕМНЫЙ МАРКЕР ЗАКРЫТОГО СЕКТОРА","aspect":"wide"}]},{"title":"СОВЕТСКОЕ СОКРЫТИЕ И ПОВТОРНОЕ ОТКРЫТИЕ","paragraphs":["В советский период сведения о радиации были исключены из публичного описания района. Полуостров Витязь действовал как запретная военная зона: въезд контролировался, маршруты перекрывались, а отдельные объекты не обозначались на гражданских картах. Несмотря на режим, местные жители и приезжие неоднократно пытались проникать к бухтам и оставленным сооружениям.","В 1950-х годах ограничения начали частично снимать. Открытие происходило без раскрытия полной истории территории и без понятного населению режима радиационной безопасности. На полуостров направился постоянный и сезонный поток людей, после чего длительное облучение стало массовым, а наблюдавшиеся изменения — частью повседневной среды."],"media":[{"src":"assets/anomalies/mid-a-0001/real-entry-rain.webp","alt":"Въезд в Андреевку","caption":"ВНУТРЕННИЙ АРХИВ / ВХОД В ЗОНУ ПОСЛЕ СНЯТИЯ ОГРАНИЧЕНИЙ","aspect":"wide"}]},{"title":"ПОВТОРНОЕ ЗАСЕЛЕНИЕ И МУТАЦИИ","paragraphs":["После повторного заселения изменения проявились не одновременно. У части жителей фиксировались внешние мутации, у части — нарушения поведения, восприятия времени и реакции на электромагнитные поля. Центральная Андреевка постепенно проветривалась и перестраивалась, однако низины, старые дренажные линии, дворы над полостями и удалённые участки сохраняли значительно более устойчивое воздействие.","Современный турист может провести короткое время в центре без явных последствий, но это не означает нейтрализации зоны. Накопительный эффект особенно выражен у постоянных жителей и у людей, многократно возвращающихся на полуостров. В клиентской базе MIDGAS с Андреевкой связаны несколько самостоятельных линий мутаций."],"media":[{"src":"assets/anomalies/mid-a-0001/real-mutants-dusk.webp","alt":"Жители Андреевки в сумерках","caption":"ВНУТРЕННИЙ АРХИВ / ПОСЛЕДСТВИЯ ДЛИТЕЛЬНОГО ЗАСЕЛЕНИЯ","aspect":"wide"},{"src":"assets/anomalies/mid-a-0001/real-street.webp","alt":"Жилая улица Андреевки","caption":"ГЛУБИННЫЙ СЕКТОР / ЖИЛАЯ ЛИНИЯ НАД СТАРЫМИ ПОЛОСТЯМИ","aspect":"wide"},{"src":"assets/anomalies/mid-a-0001/real-market-rain.webp","alt":"Рынок во внутреннем секторе Андреевки","caption":"ВНУТРЕННИЙ РЫНОК / СМЕШЕНИЕ ПОСТОЯННОГО И СЕЗОННОГО НАСЕЛЕНИЯ","aspect":"wide"},{"src":"assets/anomalies/mid-a-0001/real-market-fog.webp","alt":"Сезонный рынок Андреевки в дождь","caption":"СЕЗОННЫЙ РЫНОК / КОНТАКТ ТУРИСТИЧЕСКОГО ПОТОКА С ПОСТОЯННЫМ НАСЕЛЕНИЕМ","aspect":"wide"},{"src":"assets/anomalies/mid-a-0001/real-lower-settlement.webp","alt":"Нижний жилой сектор Андреевки","caption":"НИЖНИЙ СЕКТОР / СТОК, ПОСТОЯННОЕ НАСЕЛЕНИЕ И БЕЗНАДЗОРНЫЕ ЖИВОТНЫЕ","aspect":"wide"}],"relatedRecords":[{"type":"client","id":"MID-C-0003","label":"MID-C-0003 / КОМАР-МУТАНТ"},{"type":"client","id":"MID-C-0011","label":"MID-C-0011 / КЕПОЧНИК-МУТАНТ"},{"type":"client","id":"MID-C-0020","label":"MID-C-0020 / МУТАНТ ГВАРДЕЙ"},{"type":"client","id":"MID-C-0021","label":"MID-C-0021 / МАНЬЯК-МУТАНТ"},{"type":"client","id":"MID-C-0024","label":"MID-C-0024 / АННА МАЦКЕВИЧ"}]},{"title":"ПОДОРОЖНИЧЕСКИЕ ОБЩИНЫ","paragraphs":["В глубинных секторах сформировались общины, которые объясняют последствия облучения через народную медицину, ритм и духовную перестройку организма. Основным средством считается подорожник: его прикладывают к коже, настаивают, выращивают возле отмеченных участков и используют как индикатор состояния почвы. Практики не устраняют источник, но создают устойчивую местную систему поведения вокруг него.","Ритмическая модель описывает зону как повреждённый контур, в котором событие XIX века продолжает повторяться в ослабленной форме. Контактные и эзотерические трактовки используются институтом как вспомогательные языки наблюдения, но не заменяют дозиметрию и отбор проб."],"media":[{"src":"assets/anomalies/mid-a-0001/real-radioactive-yard.webp","alt":"Община во внутреннем дворе Андреевки","caption":"ОБЩИНА / БЫТОВОЙ КОНТАКТ С РАДИОАКТИВНЫМ СЕКТОРОМ","aspect":"wide"},{"src":"assets/anomalies/mid-a-0001/real-beach-sectants.webp","alt":"Члены общины на пляже Андреевки","caption":"ПРИБРЕЖНАЯ ОБЩИНА / СЕЗОННЫЙ ЦИКЛ","aspect":"wide"},{"src":"assets/anomalies/mid-a-0001/real-coast-fog.webp","alt":"Прибрежный сектор Андреевки в тумане","caption":"ПРИБРЕЖНЫЙ СЕКТОР / ОБЩИННЫЙ МАРШРУТ ВО ВРЕМЯ ТУМАНА","aspect":"wide"}],"relatedRecords":[{"type":"client","id":"MID-C-0018","label":"MID-C-0018 / ПОДОРОЖНИЦА ЛЮСИНДА"},{"type":"client","id":"MID-C-0002","label":"MID-C-0002 / ИРИНА ПОДЗОРОВА"},{"type":"client","id":"MID-C-0008","label":"MID-C-0008 / ЕВДОКИЯ ЛУЧЕЗАРНОВА"}]},{"title":"ВОЕННЫЕ ОБЪЕКТЫ И ИЗОЛЯТОРЫ","paragraphs":["Вокруг Андреевки сохраняется сеть действующих и законсервированных объектов. По классификации MIDGAS она включает пункты наблюдения, технические хранилища, изоляторы для нестабильных мутантов и камеры для материалов с остаточным излучением. Часть сооружений соединена со старыми подземными коридорами.","Точные координаты в публичную версию карточки не включаются. Самовольный вход в бетонные сооружения, вентиляционные шахты, штольни и ограждённые участки запрещён: локальный фон может резко отличаться от показаний на соседней открытой территории."]},{"title":"РАДИАЦИОННЫЙ ПРОФИЛЬ","paragraphs":["Основным устойчивым маркером зоны является цезий-137. Распределение неоднородно: осадки и поверхностный сток переносят загрязнение в низины, старые канавы и почву вокруг подземных камер. Корневая система растений и донные отложения способны удерживать след дольше, чем открытые каменные и асфальтированные поверхности.","Снижение фона в центре связано с выветриванием, заменой грунта, строительством и постоянным движением людей. Оно не распространяется автоматически на весь полуостров. Архив не публикует универсальное числовое значение, потому что замеры привязаны к точке, погоде, глубине отбора и конкретному сезону экспедиции.","Отдельный контур образует биологический перенос. Животные, питающиеся растительностью и органическими отходами в низинах, накапливают цезий-137 в тканях и переносят загрязнение за пределы одной точки выпаса. Молоко, мясо и навоз из глубинных секторов рассматриваются как самостоятельные пробы и не объединяются с обычными пищевыми образцами."],"media":[{"src":"assets/anomalies/mid-a-0001/real-foodchain-cattle.webp","alt":"Домашнее животное на загрязнённом участке Андреевки","caption":"БИОЛОГИЧЕСКИЙ ПЕРЕНОС / ВЫПАС НА ЗАГРЯЗНЁННОМ БЫТОВОМ ГРУНТЕ","aspect":"wide"}]},{"title":"ЕЖЕГОДНЫЕ ЭКСПЕДИЦИИ MIDGAS","paragraphs":["Институт проводит экспедицию в Андреевку ежегодно. Маршрут включает повторные контрольные точки, пешеходную гамма-съёмку, проверку прибрежных и глубинных участков, отбор проб почвы и воды, фотофиксацию изменений и сопоставление показаний с предыдущими циклами.","Группа использует персональные дозиметры и дублирующие приборы, фиксирует координаты отдельно от основного журнала и проходит очистку оборудования после выхода из глубинных секторов. Расположенная неподалёку вторая штаб-квартира MIDGAS служит базой подготовки, хранения образцов и первичной обработки полевых данных."],"media":[{"src":"assets/anomalies/mid-a-0001/real-coastal-route.webp","alt":"Полевой маршрут MIDGAS вдоль побережья Андреевки","caption":"ЭКСПЕДИЦИОННЫЙ МАРШРУТ / ВЫХОД К ПРИБРЕЖНОЙ КОНТРОЛЬНОЙ ТОЧКЕ","aspect":"wide"}]},{"title":"ТЕКУЩАЯ ОЦЕНКА И ПРОТОКОЛ ДОСТУПА","paragraphs":["Андреевская аномалия считается активной. Курортный фасад не отменяет внутреннего режима территории. Сотрудникам запрещено вскрывать грунт, входить в бункеры и приближаться к изоляторам без задания уровня D4. Любое необычное состояние человека после возвращения регистрируется как отдельное наблюдение, даже если первоначальные показания приборов находились в рабочем диапазоне.","Посещение открытой части не приравнивается к работе в глубинном секторе, однако длительное проживание и регулярные возвращения требуют отдельного контроля. Карточка остаётся открытой для дополнений после каждого экспедиционного цикла."]}],"research":{"code":"AR-1950/2025","title":"ДОЛГОВРЕМЕННОЕ РАДИАЦИОННОЕ И БИОЛОГИЧЕСКОЕ ИССЛЕДОВАНИЕ","period":"1950—2025","intro":"Сводный модельный ряд лаборатории MIDGAS объединяет восстановленные журналы наблюдений, повторные замеры на контрольных точках и результаты ежегодных экспедиций. Значения приведены к единой методике 2025 года. Ранние интервалы реконструированы по сохранившимся полевым записям и образцам.","methodology":[["Контрольные точки","Центр, пляж, низина, Замок Янковского, бункерный сектор"],["Полевые методы","Гамма-дозиметрия, маршрутная съёмка, GPS-привязка"],["Лабораторные методы","Гамма-спектрометрия грунта, радиометрия воды"],["Биологический контур","Реестр случаев на 1 000 постоянных жителей"],["Последний цикл","Экспедиция 2025 / 184 точки / 62 образца"],["Основной нуклид","Цезий-137"]],"charts":[{"type":"line","number":"01","title":"МОЩНОСТЬ АМБИЕНТНОЙ ДОЗЫ ПО СЕКТОРАМ","unit":"мкЗв/ч","note":"Логарифмический ряд медианных летних измерений с расчётным 95-процентным коридором. Архивный контрольный уровень: 0,30 мкЗв/ч.","labels":["1950","1960","1970","1980","1990","2000","2010","2020","2025"],"threshold":0.3,"scale":"log","uncertainty":0.14,"metrics":[["ПИК 1950","386 мкЗв/ч"],["ПИК 2025","84 мкЗв/ч"],["ПРЕВЫШЕНИЕ","×280"]],"analysis":["Даже наиболее очищенная прибрежная точка в 2025 году сохраняет значение 1,7 мкЗв/ч — в 5,7 раза выше внутреннего контрольного уровня MIDGAS. Центральный сектор превышает его в 16 раз.","Бункерная линия снижается медленнее остальных. Форма кривой указывает не на остаточный поверхностный след, а на продолжающееся поступление из заглублённого источника."],"series":[{"name":"Центр","values":[28,24,20,17,14,11,8.2,5.6,4.8]},{"name":"Пляж","values":[13.8,11.7,9.4,7.8,6.1,4.4,3.2,2.1,1.7]},{"name":"Низина","values":[162,151,139,124,108,88,64,36,28]},{"name":"Замок","values":[96,87,78,68,57,45,33,21,16]},{"name":"Бункерный сектор","values":[386,360,329,294,250,207,169,112,84]}]},{"type":"bar","number":"02","title":"ЦЕЗИЙ-137 В ВЕРХНЕМ СЛОЕ ГРУНТА","unit":"Бк/кг","note":"Логарифмическая шкала. Сухая масса, горизонт 0—10 см, экспедиция 2025. Столбец — медиана серии из 5—9 проб.","labels":["Пляж","Центр","Рынок","Замок","Низина","Бункеры"],"scale":"log","threshold":1000,"metrics":[["МАКСИМУМ","420 000 Бк/кг"],["МЕДИАНА","59 700 Бк/кг"],["КОНТРОЛЬ","1 000 Бк/кг"]],"analysis":["Загрязнение фиксируется во всех шести секторах. Даже пляжный грунт превышает лабораторный контроль в 4,8 раза, а бункерный сектор — в 420 раз.","Рынок расположен на линии сезонного поверхностного стока. Его показатель 28 400 Бк/кг объясняет перенос загрязнения в зону постоянного контакта людей с грунтом и пылью."],"series":[{"name":"Cs-137","values":[4800,12600,28400,91000,138000,420000]}]},{"type":"grouped-bar","number":"03","title":"РАДИОНУКЛИДЫ В ПРОБАХ ВОДЫ","unit":"Бк/л","note":"Отфильтрованные пробы 2025 года. Логарифмическое сопоставление удельной активности Cs-137 и Sr-90.","labels":["Бухта","Центр. колодец","Рыночный сток","Пруд низины","Бункерный ключ"],"scale":"log","metrics":[["CS-137","до 74,8 Бк/л"],["SR-90","до 31,6 Бк/л"],["ПРОБ","18"]],"analysis":["Морская вода разбавляет поступление, но бухта не является нулевой точкой. Колодец в центре уже демонстрирует устойчивую связь с загрязнённым подземным горизонтом.","Бункерный ключ и рыночный сток образуют два главных пути переноса. В этих точках вода не допускается к бытовому использованию даже после фильтрации."],"series":[{"name":"Cs-137","values":[1.8,4.6,38.4,27.2,74.8]},{"name":"Sr-90","values":[0.6,1.4,14.9,11.8,31.6]}]},{"type":"stacked-area","number":"04","title":"ЗАРЕГИСТРИРОВАННЫЕ СЛУЧАИ ОБЛУЧЕНИЯ","unit":"случаев на 1 000 жителей","note":"Накопительная пятилетняя частота по степени клинического проявления. После 1990 года включены повторные сезонные посетители.","labels":["1955","1965","1975","1985","1995","2005","2015","2020","2025"],"metrics":[["ВСЕГО 2025","918 / 1 000"],["КЛИНИЧЕСКИЕ","316 / 1 000"],["ТЯЖЁЛЫЕ","151 / 1 000"]],"analysis":["К 2025 году признаки воздействия зарегистрированы у 918 из 1 000 наблюдаемых постоянных жителей. У 467 случаев присутствуют клинические либо тяжёлые проявления.","Рост после 1990 года связан не только с улучшением регистрации: в реестр вошли люди, возвращавшиеся в Андреевку не менее трёх сезонов подряд."],"series":[{"name":"Субклинические","values":[62,94,138,191,244,309,382,418,451]},{"name":"Клинические","values":[19,32,51,76,111,158,224,274,316]},{"name":"Тяжёлые","values":[5,9,15,24,39,61,94,123,151]}]},{"type":"heatmap","number":"05","title":"ИНДЕКС НАБЛЮДАЕМЫХ МУТАЦИЙ","unit":"случаев на 1 000 жителей","note":"Когортная тепловая матрица. Категории пересекаются: один клиент может учитываться в нескольких рядах.","labels":["1960","1970","1980","1990","2000","2010","2020","2025"],"metrics":[["МАКСИМУМ","480 / 1 000"],["КАТЕГОРИЙ","4"],["КОГОРТА","1 842"]],"analysis":["Наиболее распространён нейроповеденческий контур: к 2025 году он отмечен у 48 процентов наблюдаемой когорты. Ритмические нарушения занимают второе место.","Электромагнитные проявления растут быстрее остальных после 2000 года. Этот переход совпадает с массовым распространением цифровой техники среди постоянных жителей."],"series":[{"name":"Соматические","shortName":"СОМАТ.","values":[18,31,52,81,126,188,276,320]},{"name":"Нейроповеденческие","shortName":"НЕЙРОПОВ.","values":[34,57,91,143,216,305,422,480]},{"name":"Электромагнитные","shortName":"ЭЛ.-МАГН.","values":[4,9,18,36,79,142,236,275]},{"name":"Ритмические","shortName":"РИТМИЧ.","values":[9,18,37,68,126,205,318,360]}]},{"type":"line","number":"06","title":"ВЕРТИКАЛЬНЫЙ ПРОФИЛЬ CS-137 В ГРУНТЕ","unit":"Бк/кг","note":"Логарифмический профиль составных кернов 2025 года. Рост на глубине в бункерном секторе указывает на заглублённый источник.","labels":["0—5 см","5—10 см","10—20 см","20—30 см","30—50 см"],"scale":"log","uncertainty":0.09,"metrics":[["ПИК КЕРНА","780 000 Бк/кг"],["ГЛУБИНА","50 см"],["КЕРНОВ","12"]],"analysis":["В центре и низине активность уменьшается с глубиной, что соответствует преимущественно поверхностному переносу. В бункерном секторе наблюдается обратный профиль.","На горизонте 30—50 см значение достигает 780 000 Бк/кг. Инверсия считается главным инструментальным доказательством поступления из подземного комплекса."],"series":[{"name":"Центр","values":[13200,10400,6800,3900,2100]},{"name":"Низина","values":[152000,139000,98000,66000,42000]},{"name":"Бункерный сектор","values":[380000,420000,510000,650000,780000]}]},{"type":"line","number":"07","title":"МАРШРУТНЫЙ ПРОФИЛЬ ЭКСПЕДИЦИИ 2025","unit":"мкЗв/ч","note":"Логарифмический профиль пути от прибрежной контрольной точки к бункерному сектору; расстояние по маршруту — 8,4 км.","labels":["0,0","1,2","2,4","3,6","4,8","6,0","7,2","8,4 км"],"scale":"log","uncertainty":0.16,"threshold":0.3,"metrics":[["МАКСИМУМ","688 мкЗв/ч"],["МЕДИАНА ФИНАЛ","214 мкЗв/ч"],["МАРШРУТ","8,4 км"]],"analysis":["Первые 2,4 км уже не соответствуют безопасному транзиту. После отметки 4,8 км профиль переходит в режим, при котором время нахождения группы ограничивается индивидуальной накопленной дозой.","Финальный пик 688 мкЗв/ч зарегистрирован у вентиляционной линии. Разрыв между медианой и максимумом показывает чрезвычайно локальный характер выходов из грунта."],"series":[{"name":"Медиана","values":[1.2,2.8,6.4,19,57,41,126,214]},{"name":"Максимум","values":[4.6,10.8,24,82,186,143,402,688]}]}],"sampleTable":{"title":"КОНТРОЛЬНЫЕ ПРОБЫ / ЭКСПЕДИЦИЯ 2025","headers":["Код","Сектор","Материал","Глубина","Cs-137","Sr-90","Оценка"],"rows":[["A25-S04","Центр","Грунт","0—10 см","12 600 Бк/кг","960 Бк/кг","Высокий"],["A25-S17","Низина","Грунт","0—10 см","138 000 Бк/кг","11 400 Бк/кг","Критический"],["A25-S31","Бункеры","Грунт","30—50 см","780 000 Бк/кг","63 200 Бк/кг","Экстремальный"],["A25-W03","Бухта","Вода","Поверхность","1,80 Бк/л","0,60 Бк/л","Повышен"],["A25-W11","Рыночный сток","Вода","Поверхность","38,40 Бк/л","14,90 Бк/л","Критический"],["A25-W19","Бункерный ключ","Вода","Источник","74,80 Бк/л","31,60 Бк/л","Экстремальный"]]}},"editorRelations":[{"type":"client","id":"MID-C-0003","label":"КОМАР МУТАНТ"},{"type":"client","id":"MID-C-0011","label":"КЕПОЧНИК МУТАНТ"},{"type":"client","id":"MID-C-0020","label":"МУТАНТ ГВАРДЕЙ"},{"type":"client","id":"MID-C-0021","label":"МАНЬЯК МУТАНТ"},{"type":"client","id":"MID-C-0024","label":"АННА МАЦКЕВИЧ"},{"type":"client","id":"MID-C-0018","label":"ПОДОРОЖНИЦА ЛЮСИНДА"},{"type":"client","id":"MID-C-0002","label":"ИРИНА ПОДЗОРОВА"},{"type":"client","id":"MID-C-0008","label":"ЕВДОКИЯ ЛУЧЕЗАРНОВА"},{"type":"incident","id":"MID-I-0001","label":"ИНЦИДЕНТ СТРАХОМАХА.EXE"},{"type":"incident","id":"MID-I-0002","label":"КРОВОЛУНАНИЕ"}],"editorRelationsVersion":1}'::jsonb, null);

