  insert into public.records (record_type, content, cover_path)
  values ('incident', '{"id":"MID-I-0001","kind":"INCIDENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Полное техническое досье MIDGAS. Активное расследование.","duplicateOf":null,"name":"ИНЦИДЕНТ СТРАХОМАХА.EXE","alias":"Деструктивный криптографический вирус / визуальный комплекс «Страхомаха»","cardType":"Активная массовая кибераномалия","image":"assets/incidents/mid-i-0001/strakhomakha-new-cover.webp","summary":"СТРАХОМАХА.EXE — продолжающаяся массовая кампания заражений, впервые зарегистрированная поздней осенью 2023 года. В случайный момент заражённый компьютер блокируется, данные шифруются без требования выкупа, а на экране появляется одно из изображений неизвестных субъектов. Пиковая фаза пришлась на лето 2024 года; совокупное число затронутых устройств превысило один миллион.","fields":[["Тип","Деструктивный криптографический вирус"],["Статус","Активен / продолжается распространение"],["Первое обнаружение","Ноябрь 2023 года"],["Пиковая фаза","Июнь—август 2024 года"],["Затронуто устройств","> 1 300 000"],["Уровень угрозы","T5 / критический"],["Уровень доступа","D4 / ограниченный"],["Требование выкупа","Отсутствует"],["Состояние данных","Зашифрованы / восстановление не подтверждено"],["Визуальных классов","4 основных / 17 повреждённых вариантов"],["Предполагаемая связь","MID-A-0001 / Андреевская аномалия"]],"sections":[{"title":"ПЕРВИЧНАЯ РЕГИСТРАЦИЯ / ОСЕНЬ 2023","paragraphs":["Первые достоверно связанные обращения поступили в конце осени 2023 года. Пользователи из разных городов сообщали об одинаковой последовательности: компьютер продолжал работать без заметных признаков заражения, затем внезапно переставал принимать команды, все окна исчезали, а поверх интерфейса разворачивалось низкокачественное изображение неизвестного человека или группы людей.","В течение первых недель случаи считались несвязанными повреждениями системы. Общий инцидент был выделен после обнаружения одинаковых визуальных артефактов, совпадающего порядка блокировки накопителей и отсутствия какого-либо требования выкупа. Рабочее название «Страхомаха» было взято из ранних пользовательских описаний и закреплено институтом как обозначение всего комплекса."]},{"title":"ПОСЛЕДОВАТЕЛЬНОСТЬ ЗАРАЖЕНИЯ","paragraphs":["После проникновения комплекс способен находиться в скрытой фазе от нескольких минут до нескольких недель. В это время обычная работа компьютера сохраняется. Непосредственно перед активацией фиксируются короткие задержки интерфейса, пропадание отдельных системных журналов, повторное подключение накопителей и единичный всплеск сетевой активности.","В активной фазе блокируются клавиатура, мышь и стандартные средства завершения работы. На экран выводится изображение Страхомахи; параллельно содержимое пользовательских каталогов, архивов, рабочих баз и подключённых дисков переходит в зашифрованное состояние. После перезапуска изображение может исчезнуть, однако данные остаются недоступными, а система обычно перестаёт загружаться штатно.","Порядок действий не полностью одинаков на всех устройствах. Это указывает либо на несколько сборок вируса, либо на единую адаптивную систему, меняющую поведение в зависимости от содержимого компьютера."]},{"title":"ПИКОВАЯ ФАЗА / ЛЕТО 2024","paragraphs":["Резкое ускорение распространения началось в июне 2024 года. От одиночных домашних компьютеров инфекция перешла к небольшим организациям, учебным кабинетам, торговым точкам и локальным сетям. Максимальная суточная регистрация пришлась на вторую половину июля.","Во время пиковой фазы появились групповые варианты изображения и первые кадры с собакообразным субъектом. Одновременно увеличилась доля случаев, в которых шифрование затрагивало не только локальные диски, но и доступные сетевые хранилища. К началу сентября интенсивность снизилась, однако полного прекращения распространения не произошло."]},{"title":"КОРПУС ИЗОБРАЖЕНИЙ СТРАХОМАХИ","paragraphs":["Первая пара кадров относится к раннему корпусу, полученному с домашних компьютеров в декабре 2023 года. На обоих изображениях сохраняются одинаковая дистанция до камеры, тёмный фон и нижняя светлая граница, похожая на край стола или корпуса монитора. Различие положения лица объясняется либо последовательной съёмкой, либо программной сборкой соседних кадров. Исходные файлы поступили из независимых источников, но имеют близкие параметры сжатия и одинаковый набор повреждённых цветовых каналов.","Вторая пара выделена в класс фронтальной деформации. Главный субъект расположен по центру, а изменение пропорций затрагивает рот, нижнюю часть лица и контур щёк. Следов обычной ручной ретуши не обнаружено: границы деформации совпадают с участками компрессионного шума, возникающего уже после записи изображения. Это не доказывает автоматическое происхождение материала, однако указывает, что опубликованные копии прошли единый этап обработки до попадания на заражённые устройства.","Третья пара показывает смещение точки наблюдения вправо и появление дополнительных деталей помещения. Экспозиция остаётся недостаточной, но в тенях просматриваются вертикальная плоскость и участок светлой поверхности. Сотрудники лаборатории сопоставили геометрию с другими вариантами и пришли к выводу, что съёмка проводилась в одном небольшом помещении. Разница масштаба объясняется не сменой камеры, а приближением субъекта к объективу или цифровым увеличением исходного кадра.","Четвёртая пара содержит признаки групповой композиции: рядом с основным лицом появляются фрагменты второй фигуры и наложенные контуры, не совпадающие по резкости. На одном изображении дополнительный силуэт читается как человек, на другом — как смешанная форма с вытянутой нижней частью. Рабочая классификация не рассматривает эти детали как самостоятельных существ без подтверждения из отдельного ракурса; они отмечены как визуальные фрагменты неизвестного происхождения.","Пятая пара получена во время пиковой волны июля 2024 года. Изображения демонстрировались на компьютерах из разных сетей с интервалом менее трёх часов. Совпадение фоновых деталей и незначительное различие положения глаз позволяют предполагать, что вирус выбирал соседние кадры из более длинной последовательности. Телеметрия не показала загрузку крупных файлов непосредственно перед блокировкой, поэтому набор мог находиться на устройствах заранее в скрытом виде.","Шестая пара отличается повышенной контрастностью и частичной потерей полутонов. Визуальная информация в области волос и одежды почти исчезает, тогда как центральная часть лица сохраняется. Такой профиль повреждения повторялся на устройствах с различными видеокартами и версиями операционной системы, что делает аппаратный сбой маловероятным. Институт относит эти файлы к намеренно подготовленным вариантам, рассчитанным на быстрое распознавание даже при низком качестве экрана.","Седьмая пара зарегистрирована в учебной и офисной сетях. В обоих случаях изображение появилось после завершения шифрования общих каталогов, но до остановки системного журнала. На кадрах заметны сдвиг лица и участки, похожие на результат совмещения двух экспозиций. Совпадение времени появления с финальной стадией заражения подтверждает, что визуальный материал используется как маркер завершённой операции, а не как элемент начального проникновения.","Восьмая пара содержит наиболее выраженные нарушения анатомических пропорций. Лаборатория отдельно проверила гипотезы о панорамной съёмке, фильтрах мобильной камеры и растяжении при изменении формата. Ни одна из них не воспроизвела весь набор искажений одновременно. В отчёте материал оставлен без окончательной интерпретации: допустимы как преднамеренная цифровая обработка, так и сборка из нескольких исходных фотографий с последующим многократным пересжатием.","Девятая пара завершает подтверждённый корпус из восемнадцати кадров. Она объединяет признаки предыдущих классов: тёмное помещение, фронтальный ракурс, локальную деформацию и нестабильные границы фигуры. Файлы обнаружены в 2026 году, но их внутренние метки совпадают с шаблонами пиковой волны 2024 года. Это может означать повторное использование старого набора оператором либо длительное хранение материала внутри неактивных копий комплекса."],"media":[{"src":"assets/incidents/mid-i-0001/41631634.jpg","alt":"Материал Страхомахи, контрольный кадр 01","caption":"КАДР SMX-IMG-01 / РАННЯЯ ФРОНТАЛЬНАЯ ФИКСАЦИЯ / ДЕКАБРЬ 2023","aspect":"wide","afterParagraph":0},{"src":"assets/incidents/mid-i-0001/photo_1_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 02","caption":"КАДР SMX-IMG-02 / СМЕЩЕНИЕ ЛИЦЕВОГО КОНТУРА / ИСХОДНАЯ ВОЛНА","aspect":"wide","afterParagraph":0},{"src":"assets/incidents/mid-i-0001/photo_2_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 03","caption":"КАДР SMX-IMG-03 / КЛАСС ФРОНТАЛЬНОЙ ДЕФОРМАЦИИ / ВАРИАНТ A","aspect":"wide","afterParagraph":1},{"src":"assets/incidents/mid-i-0001/photo_3_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 04","caption":"КАДР SMX-IMG-04 / КЛАСС ФРОНТАЛЬНОЙ ДЕФОРМАЦИИ / ВАРИАНТ B","aspect":"wide","afterParagraph":1},{"src":"assets/incidents/mid-i-0001/photo_5_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 05","caption":"КАДР SMX-IMG-05 / ПРАВОСТОРОННЕЕ СМЕЩЕНИЕ ТОЧКИ НАБЛЮДЕНИЯ","aspect":"wide","afterParagraph":2},{"src":"assets/incidents/mid-i-0001/photo_7_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 06","caption":"КАДР SMX-IMG-06 / УВЕЛИЧЕННЫЙ ФРАГМЕНТ / ЕДИНЫЙ ФОН ПОМЕЩЕНИЯ","aspect":"wide","afterParagraph":2},{"src":"assets/incidents/mid-i-0001/photo_8_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 07","caption":"КАДР SMX-IMG-07 / ГРУППОВАЯ КОМПОЗИЦИЯ / ДОПОЛНИТЕЛЬНЫЙ СИЛУЭТ","aspect":"wide","afterParagraph":3},{"src":"assets/incidents/mid-i-0001/photo_10_2026-07-12_18-19-56.jpg","alt":"Материал Страхомахи, контрольный кадр 08","caption":"КАДР SMX-IMG-08 / СМЕШАННЫЙ КОНТУР / НЕДОСТАТОЧНО ДАННЫХ","aspect":"wide","afterParagraph":3},{"src":"assets/incidents/mid-i-0001/photo_11_2026-07-12_18-19-56.jpg","alt":"Материал Страхомахи, контрольный кадр 09","caption":"КАДР SMX-IMG-09 / ПИКОВАЯ ВОЛНА / ИЮЛЬ 2024 / ВАРИАНТ A","aspect":"wide","afterParagraph":4},{"src":"assets/incidents/mid-i-0001/photo_12_2026-07-12_18-19-56.jpg","alt":"Материал Страхомахи, контрольный кадр 10","caption":"КАДР SMX-IMG-10 / ПИКОВАЯ ВОЛНА / ИЮЛЬ 2024 / ВАРИАНТ B","aspect":"wide","afterParagraph":4},{"src":"assets/incidents/mid-i-0001/photo_13_2026-07-12_18-19-56.jpg","alt":"Материал Страхомахи, контрольный кадр 11","caption":"КАДР SMX-IMG-11 / ВЫСОКОКОНТРАСТНАЯ КОПИЯ / ПОТЕРЯ ПОЛУТОНОВ","aspect":"wide","afterParagraph":5},{"src":"assets/incidents/mid-i-0001/photo_14_2026-07-12_18-19-56.jpg","alt":"Материал Страхомахи, контрольный кадр 12","caption":"КАДР SMX-IMG-12 / ВЫСОКОКОНТРАСТНАЯ КОПИЯ / ЦЕНТРАЛЬНЫЙ ФРАГМЕНТ","aspect":"wide","afterParagraph":5},{"src":"assets/incidents/mid-i-0001/photo_15_2026-07-12_18-19-56.jpg","alt":"Материал Страхомахи, контрольный кадр 13","caption":"КАДР SMX-IMG-13 / УЧЕБНАЯ СЕТЬ / ФИНАЛЬНАЯ ФАЗА ШИФРОВАНИЯ","aspect":"wide","afterParagraph":6},{"src":"assets/incidents/mid-i-0001/photo_16_2026-07-12_18-19-56.jpg","alt":"Материал Страхомахи, контрольный кадр 14","caption":"КАДР SMX-IMG-14 / ОФИСНАЯ СЕТЬ / ДВОЙНАЯ ЭКСПОЗИЦИЯ","aspect":"wide","afterParagraph":6},{"src":"assets/incidents/mid-i-0001/photo_17_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 15","caption":"КАДР SMX-IMG-15 / АНАТОМИЧЕСКОЕ ИСКАЖЕНИЕ / КЛАСС D-1","aspect":"wide","afterParagraph":7},{"src":"assets/incidents/mid-i-0001/photo_18_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 16","caption":"КАДР SMX-IMG-16 / АНАТОМИЧЕСКОЕ ИСКАЖЕНИЕ / КЛАСС D-2","aspect":"wide","afterParagraph":7},{"src":"assets/incidents/mid-i-0001/photo_19_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 17","caption":"КАДР SMX-IMG-17 / ПОЗДНЯЯ РЕГИСТРАЦИЯ / ПОВТОР ШАБЛОНА 2024 ГОДА","aspect":"wide","afterParagraph":8},{"src":"assets/incidents/mid-i-0001/photo_20_2026-07-12_18-21-40.jpg","alt":"Материал Страхомахи, контрольный кадр 18","caption":"КАДР SMX-IMG-18 / КОНТРОЛЬНЫЙ ВАРИАНТ / АРХИВ 2026 ГОДА","aspect":"wide","afterParagraph":8}]},{"title":"НЕИЗВЕСТНЫЕ СУБЪЕКТЫ","paragraphs":["Личности изображённых людей не установлены. По кадрам невозможно надёжно определить возраст, происхождение и даже точное число участников: алгоритмические искажения переносят элементы одного лица на другое. Тем не менее повторяются форма головы, одежда, положение плеч и характерные повреждения, поэтому институт считает, что в основе корпуса находится ограниченная группа реальных субъектов.","У нескольких фигур отсутствуют различимые глаза, части носа или нормальный контур рта. Это может быть результатом намеренной обработки, ошибочного восстановления повреждённого файла либо реальным состоянием изображённых людей. Собакообразная фигура также повторяется и не считается случайным эффектом компрессии."]},{"title":"ГИПОТЕЗА АНДРЕЕВСКОГО ИЗОЛЯТОРА","paragraphs":["Одна из основных версий связывает исходную комнату с закрытым объектом на полуострове Витязь. В пользу версии приводятся повторяющиеся признаки длительной изоляции, возможные мутации субъектов, нестандартное освещение и сходство отдельных помех с материалами, полученными в глубинных секторах Андреевки.","В рамках этой модели изображения показывают мутантов, удерживаемых в техническом или военном помещении. Вирус может быть средством передачи кадров наружу, намеренной системой устрашения либо побочным продуктом оборудования изолятора. Прямого подтверждения местоположения комнаты пока нет."],"relatedRecords":[{"type":"anomaly","id":"MID-A-0001","label":"MID-A-0001 / АНДРЕЕВСКАЯ АНОМАЛИЯ"},{"type":"client","id":"MID-C-0024","label":"MID-C-0024 / АННА МАЦКЕВИЧ"}]},{"title":"КРИПТОГРАФИЧЕСКОЕ ВОЗДЕЙСТВИЕ","paragraphs":["Зашифрованные файлы сохраняют исходный размер лишь приблизительно и обладают высокой равномерностью данных. Единого расширения, записки оператора или открытого идентификатора жертвы нет. На разных волнах менялись служебные заголовки, но основной результат оставался одинаковым: практическая невозможность извлечь содержимое стандартными средствами.","Ключевой материал на поражённом компьютере не обнаружен. Анализ показывает, что часть операции завершается до появления изображения, а визуальный кадр отмечает не начало, а финал уничтожения доступа. Подтверждённых случаев полного расшифрования без резервной копии в архиве MIDGAS нет."]},{"title":"КАНАЛЫ РАСПРОСТРАНЕНИЯ","paragraphs":["Единого начального носителя не установлено. Волны связывались с заражёнными вложениями, изменёнными установочными пакетами, съёмными накопителями и переходом внутри локальных сетей. При этом ни один канал не объясняет все случаи: некоторые компьютеры находились вне сети в момент активации, но ранее контактировали с внешними носителями или общими архивами.","Институт разделяет канал проникновения и момент запуска. Комплекс может переноситься обычным цифровым способом, долго оставаться неактивным и получать условие запуска заранее. Само изображение не считается доказанным переносчиком, но повторная пересылка снимков затрудняет отделение первичных материалов от последующих подделок."]},{"title":"НАЗНАЧЕНИЕ КОМПЛЕКСА","paragraphs":["Отсутствие требования выкупа исключает обычную финансовую модель. Вирус расходует значительные ресурсы на скрытность, шифрование и доставку визуального материала, но не предоставляет оператору очевидного способа получить деньги или вернуть данные.","Рассматриваются четыре назначения: безвозвратное уничтожение информации; массовое психологическое воздействие; распределённая проверка устойчивости инфраструктуры; принудительная трансляция материалов из неизвестной комнаты. Ни одна версия полностью не объясняет выбор жертв и продолжающееся распространение после достижения миллионного масштаба.","Наиболее тревожная гипотеза предполагает, что повреждение компьютера является вторичной функцией. Главной целью может быть гарантированный показ изображений максимальному числу наблюдателей и регистрация их реакции через краткий сетевой отклик перед блокировкой."]},{"title":"ВОЗДЕЙСТВИЕ НА НАБЛЮДАТЕЛЕЙ","paragraphs":["Пользователи часто сообщают о сильном испуге, нарушении сна и повторном мысленном воспроизведении увиденного кадра. В ряде случаев люди утверждали, что фигуры на экране меняли положение при повторном взгляде, хотя сохранённые фотографии этого не подтверждали.","Психологический эффект усиливается невозможностью закрыть изображение и одновременным пониманием утраты данных. Поэтому отдел наблюдения разделяет собственно визуальное воздействие и реакцию на необратимое повреждение компьютера."]},{"title":"ТЕКУЩИЙ СТАТУС И ПРОТОКОЛ","paragraphs":["СТРАХОМАХА.EXE продолжает распространяться. Новые регистрации происходят волнами и включают как старые визуальные классы, так и повреждённые производные. Отсутствие новых массовых пиков не считается завершением инцидента.","При обнаружении активной фазы устройство изолируется от сети и других накопителей. Повторный запуск, самостоятельная переустановка и открытие связанных файлов на рабочей системе запрещены до создания криминалистической копии. Изображение фиксируется отдельной камерой; прямое копирование с заражённого компьютера не считается надёжным."]}],"research":{"code":"SMX-2023/2026","title":"ТЕХНИЧЕСКИЙ И ЭПИДЕМИОЛОГИЧЕСКИЙ АНАЛИЗ СТРАХОМАХИ","period":"2023—2026","intro":"Сводный ряд MIDGAS объединяет подтверждённые обращения, телеметрию из изолированных образцов и визуальную классификацию экранных материалов. Повторные регистрации одного устройства объединены в один случай; вероятные заражения приведены отдельным рядом.","methodology":[["Подтверждённые устройства","1 347 000"],["Вероятные устройства","до 1 910 000"],["Исследовано образцов","4 862"],["Визуальные классы","4 основных / 17 производных"],["Период наблюдения","Ноябрь 2023 — июль 2026"],["Статус","Распространение продолжается"]],"charts":[{"type":"line","number":"01","title":"НАКОПЛЕННОЕ ЧИСЛО ЗАРАЖЁННЫХ УСТРОЙСТВ","unit":"устройств","note":"Подтверждённые и вероятные случаи. Коридор показывает оценочную неопределённость неполных региональных журналов.","labels":["11.23","01.24","04.24","07.24","10.24","04.25","01.26","07.26"],"uncertainty":0.08,"metrics":[["ПОДТВЕРЖДЕНО","1 347 000"],["ВЕРОЯТНО","1 910 000"],["СТРАН","41"]],"analysis":["Основной скачок произошёл летом 2024 года, но кривая не вышла на горизонталь. После пика комплекс перешёл к менее заметным региональным волнам.","Разрыв между подтверждёнными и вероятными случаями увеличивается: часть домашних устройств уничтожается или переустанавливается до передачи материалов исследователям."],"series":[{"name":"Подтверждённые","values":[2800,34000,168000,492000,837000,1064000,1213000,1347000]},{"name":"Вероятные","values":[6100,71000,263000,731000,1180000,1510000,1740000,1910000]}]},{"type":"stacked-area","number":"02","title":"СТРУКТУРА ПИКОВОЙ ВОЛНЫ 2024 ГОДА","unit":"новых случаев в неделю","note":"Недельные регистрации по визуальному классу с июня по август 2024 года.","labels":["ИЮН-1","ИЮН-3","ИЮЛ-1","ИЮЛ-3","АВГ-1","АВГ-3"],"metrics":[["ПИК","68 400 / нед."],["ОДИНОЧНЫЕ","51%"],["ГРУППОВЫЕ","34%"]],"analysis":["Групповой класс появился до максимума общей волны и быстро занял треть регистраций. Собакообразный вариант возник позднее, но сохранился после снижения остальных рядов.","Структура волны подтверждает одновременное обращение нескольких вариантов, а не последовательную замену одной картинки другой."],"series":[{"name":"Одиночный","values":[8800,16200,24800,34700,29300,18100]},{"name":"Групповой","values":[2100,7300,14900,23100,19800,14200]},{"name":"Собакообразный","values":[0,900,4200,10600,14300,12800]}]},{"type":"bar","number":"03","title":"РАСПРЕДЕЛЕНИЕ ВИЗУАЛЬНЫХ КЛАССОВ","unit":"% подтверждённых активаций","note":"Доля активаций с достаточной фотографической фиксацией экрана.","labels":["S-1","G-3","C-1","BLACK","CORRUPT"],"metrics":[["S-1","46,8%"],["G-3","27,6%"],["C-1","11,4%"]],"analysis":["Одиночный кадр остаётся основным, однако почти половина активаций относится к другим классам. Повреждённые варианты объединяют семнадцать редких композиций.","Чёрный экран учитывается отдельно: криминалистические признаки совпадают со Страхомахой, но визуальный материал не выводится либо не успевает сформироваться."],"series":[{"name":"Доля","values":[46.8,27.6,11.4,5.1,9.1]}]},{"type":"grouped-bar","number":"04","title":"ДОЛЯ ЗАШИФРОВАННЫХ ДАННЫХ ПО КЛАССУ ХРАНИЛИЩА","unit":"% доступных данных","note":"Медианная доля необратимо недоступных файлов к моменту появления изображения.","labels":["Документы","Фото","Архивы","Базы","Сетевые"],"metrics":[["ЛОКАЛЬНЫЕ","до 99,2%"],["ВНЕШНИЕ","до 96,1%"],["СЕТЕВЫЕ","до 81,4%"]],"analysis":["Пользовательские документы и фотографии поражаются почти полностью. Сетевые хранилища затрагиваются реже только потому, что не каждое устройство имеет постоянные права записи.","Изображение появляется после завершения основной операции: к этому моменту медианная потеря локальных документов уже превышает 98 процентов."],"series":[{"name":"Локальный диск","values":[99.2,98.7,97.9,96.8,81.4]},{"name":"Внешний носитель","values":[96.1,95.4,93.2,88.7,42.8]}]},{"type":"heatmap","number":"05","title":"ЗАДЕРЖКА ДО АКТИВАЦИИ ПО ПРЕДПОЛАГАЕМОМУ КАНАЛУ","unit":"% случаев канала","note":"Распределение времени между вероятным проникновением и появлением изображения.","labels":["<10 МИН","<1 Ч","<24 Ч","<7 ДН","<30 ДН",">30 ДН"],"metrics":[["МЕДИАНА","3,8 суток"],["МАКСИМУМ","> 90 суток"],["СКРЫТАЯ ФАЗА","подтверждена"]],"analysis":["Для сетевого перехода характерна быстрая активация, тогда как съёмные носители и изменённые установочные пакеты часто формируют длительную скрытую фазу.","Наличие случаев свыше тридцати суток объясняет заражения компьютеров, которые в момент появления Страхомахи уже не были подключены к сети."],"series":[{"name":"Вложение","shortName":"ВЛОЖ.","values":[4,11,28,31,19,7]},{"name":"Установочный пакет","shortName":"УСТАН.","values":[2,7,19,33,27,12]},{"name":"Съёмный носитель","shortName":"НОСИТ.","values":[1,5,14,29,34,17]},{"name":"Локальная сеть","shortName":"ЛОК.СЕТЬ","values":[18,31,34,13,4,0]}]}],"sampleTable":{"title":"КОНТРОЛЬНЫЕ ОБРАЗЦЫ / КЛАССИФИКАЦИЯ","headers":["Код","Период","Класс","Субъекты","Шифрование","Связь","Статус"],"rows":[["SMX-23-0041","11.2023","S-1","1 человек","98,6%","Домашний ПК","Подтверждён"],["SMX-24-1187","06.2024","G-3","3 фигуры","99,1%","Учебная сеть","Подтверждён"],["SMX-24-2044","07.2024","C-1","Собакообразный","97,8%","Торговая точка","Подтверждён"],["SMX-24-7710","08.2024","CORRUPT","Смешанные","99,4%","Офисная сеть","Подтверждён"],["SMX-25-0318","04.2025","S-1","1 человек","96,9%","Внешний носитель","Подтверждён"],["SMX-26-0092","06.2026","G-3","3 фигуры","98,2%","Не установлен","Активный"]]}},"cardImage":"assets/incidents/mid-i-0001/strakhomakha-new-cover.webp","imageFit":"cover","editorRelations":[{"type":"anomaly","id":"MID-A-0001","label":"АНДРЕЕВСКАЯ АНОМАЛИЯ"},{"type":"client","id":"MID-C-0024","label":"АННА МАЦКЕВИЧ"}],"editorRelationsVersion":1}'::jsonb, null);

  if not exists (
    select 1 from public.records where record_code = 'MID-I-0001' and record_type = 'incident'
  ) then
    raise exception 'Unexpected permanent code while seeding MID-I-0001';
  end if;

  insert into public.records (record_type, content, cover_path)
  values ('incident', '{"id":"MID-I-0002","kind":"INCIDENT","stage":"НА САЙТЕ","loreState":"unique","loreNote":"Полное досье ритмического отдела THE MIDGAS.","duplicateOf":null,"name":"КРОВОЛУНАНИЕ","alias":"Периодическая ритмическая аномалия полного лунного цикла","cardType":"Глобальный ритмический инцидент","image":"assets/incidents/mid-i-0002/cover.webp","summary":"Кроволунание — периодическая глобальная ритмическая аномалия, возникающая один или несколько раз в год во время отдельных полнолуний. Активная фаза сопровождается перестройкой гравитационного, геомагнитного и ритмического поля Земли, раскрытием глубинных полостей и выходом мутировавших организмов. MIDGAS исследует явление более ста лет; продолжительность циклов и число существ продолжают расти.","fields":[["Тип","Планетарная ритмическая аномалия"],["Статус","Активна / повторяется ежегодно"],["Первое документирование","1894 год"],["Предполагаемый возраст","Несколько тысяч лет"],["Частота","От одного до четырёх раз в год"],["Длительность","От трёх до девяти часов"],["Классификация","I5 / глобальный ритмический инцидент"],["Уровень угрозы","T5 / критический"],["Уровень доступа","D5 / закрытый"],["Связанная запись","MID-A-0001 / Андреевская аномалия"]],"sections":[{"title":"ПЕРВОЕ НАБЛЮДЕНИЕ","paragraphs":["Первые достоверные записи относятся к концу XIX века. Во время отдельных полнолуний экспедиции отмечали резкие отклонения компасов, беспокойное поведение животных, слабые подземные толчки и появление существ из оврагов, шахт и провалов.","Сначала случаи считались несвязанными природными происшествиями. Позднее выяснилось, что они совпадают с полной Луной, повышенной геомагнитной активностью и локальными сейсмическими колебаниями. После сопоставления архивов MIDGAS признал Кроволунание самостоятельным повторяющимся инцидентом."],"media":[{"src":"assets/incidents/mid-i-0002/sector-01.webp","alt":"НАБЛЮДЕНИЕ КРОВОЛУНАНИЯ / ЖИЛОЙ СЕКТОР","caption":"НАБЛЮДЕНИЕ КРОВОЛУНАНИЯ / ЖИЛОЙ СЕКТОР","aspect":"wide"}]},{"title":"РИТМИЧЕСКАЯ МОДЕЛЬ","paragraphs":["Современная модель рассматривает Землю как сложный многослойный резонатор. Луна создаёт приливное воздействие не только на океаны, но и на земную кору; большую часть времени эти деформации слабы и не вызывают заметных последствий.","Во время Кроволунания накладываются циклы лунной гравитации, геомагнитных колебаний, солнечного ветра, внутренних сейсмических волн и остаточных ритмов древних аномальных зон. Литосфера кратковременно синхронизируется, давление в полостях меняется, старые трещины и тоннели раскрываются."],"media":[{"src":"assets/incidents/mid-i-0002/sector-02.webp","alt":"РИТМИЧЕСКАЯ ФАЗА / ТРАНСПОРТНЫЙ СЕКТОР","caption":"РИТМИЧЕСКАЯ ФАЗА / ТРАНСПОРТНЫЙ СЕКТОР","aspect":"wide"}]},{"title":"ФИЗИЧЕСКИЙ МЕХАНИЗМ","paragraphs":["Исследовательский отдел обозначает процесс как глубинный ритмический резонанс литосферы. В породах формируются низкочастотные стоячие волны, проходящие через карстовые системы, старые шахты, бункеры и искусственные хранилища.","Колебания вызывают смещение грунта, выход радиоактивных газов, изменение локального давления и усиление электромагнитных полей. Поверхность визуально остаётся неподвижной, однако приборы фиксируют слабую пульсацию почвы, напоминающую дыхание."],"media":[{"src":"assets/incidents/mid-i-0002/sector-03.webp","alt":"КРОВОЛУНАНИЕ / ПРОМЫШЛЕННЫЙ ПЕРИМЕТР","caption":"КРОВОЛУНАНИЕ / ПРОМЫШЛЕННЫЙ ПЕРИМЕТР","aspect":"wide"}]},{"title":"РИТМИЧЕСКАЯ СОСТАВЛЯЮЩАЯ","paragraphs":["В момент максимума возникает повторяющийся импульс ниже порога человеческого слуха. Он воздействует на нервную систему, поведение животных и биологические процессы глубинных организмов.","MIDGAS считает этот инфразвуковой ритм сигналом пробуждения. Существа реагируют на него как на сезонный призыв и начинают двигаться к поверхности ещё до видимого изменения Луны."],"media":[{"src":"assets/incidents/mid-i-0002/sector-04.webp","alt":"ПРЕДМАКСИМАЛЬНАЯ ФАЗА / ПОВЕРХНОСТНЫЕ ЖИВОТНЫЕ","caption":"ПРЕДМАКСИМАЛЬНАЯ ФАЗА / ПОВЕРХНОСТНЫЕ ЖИВОТНЫЕ","aspect":"wide"}]},{"title":"ВЫХОД СУЩЕСТВ","paragraphs":["Массовый выход начинается незадолго до максимальной фазы. Организмы появляются из вентиляционных шахт, подвалов, болот, карстовых провалов, прибрежных пещер, заброшенных бункеров и трещин в грунте.","Большинство дезориентировано светом и быстро перемещается между тёмными участками. Некоторые формы агрессивны, другие ищут воду, тепло или электромагнитные источники. После цикла многие возвращаются под землю; оставшиеся погибают, замирают или формируют поверхностные мутантные линии."],"media":[{"src":"assets/incidents/mid-i-0002/sector-05.webp","alt":"МАКСИМАЛЬНАЯ ФАЗА / ГОРОДСКАЯ ПАНОРАМА","caption":"МАКСИМАЛЬНАЯ ФАЗА / ГОРОДСКАЯ ПАНОРАМА","aspect":"wide"}]},{"title":"БИОЛОГИЧЕСКАЯ ГИПОТЕЗА","paragraphs":["Глубинные организмы, предположительно, зависят от специфического давления и состава воздуха. В обычных условиях поверхность для них непригодна.","Во время Кроволунания у разломов растёт концентрация радона, озона, сернистых соединений и ионизированных частиц, меняется электрический потенциал почвы. Кратковременная среда приближается к условиям подземных полостей и позволяет мутантам выходить без немедленного разрушения тканей. После нормализации атмосферы организмы ослабевают."]},{"title":"ПРОИСХОЖДЕНИЕ МУТАНТОВ","paragraphs":["Единого происхождения не установлено. Часть объектов похожа на сильно изменённых людей и животных; другие не соответствуют известным биологическим линиям.","Рассматриваются длительная изоляция, радиационные мутации, древние энергетические системы, искусственное выведение и адаптация к закрытым объектам. Андреевские формы выделены отдельно: они устойчивы к радиации, имеют деформации конечностей и резко реагируют на низкочастотный ритм."]},{"title":"УСИЛЕНИЕ ЯВЛЕНИЯ","paragraphs":["До середины XX века Кроволунание происходило реже и затрагивало ограниченные территории. После 1970-х продолжительность активных фаз начала увеличиваться.","С конца 2010-х фиксируются более сильные геомагнитные отклонения, новые типы существ и массовые выходы там, где прежде наблюдались только слабые признаки. Рабочая версия предполагает постепенное соединение подземных полостей в единую сеть."]},{"title":"ОСНОВНЫЕ КЛАССЫ СУЩЕСТВ","paragraphs":["Поверхностные мутанты способны оставаться наверху после завершения цикла. Подземные гуманоиды сохраняют человеческие пропорции, но отличаются кожей, глазами, конечностями и органами дыхания.","Крупные четвероногие формы быстро перемещаются у лесов, болот и промышленных зон. Неидентифицированные биологические объекты имеют неопределимую исходную анатомию и выраженно реагируют на свет, электричество и звук."]},{"title":"АНДРЕЕВСКИЙ СЕКТОР","paragraphs":["Андреевская аномалия считается одним из крупнейших центров Кроволунания. Перед активной фазой растёт гамма-фон, меняется уровень воды, усиливаются электромагнитные помехи и фиксируется движение под грунтом.","Особенно опасны болота, закрытые военные объекты, дренажные линии, подземные камеры и территория замка Янковского. Предполагается, что под полуостровом Витязь расположен один из крупнейших резервуаров мутировавших организмов."]},{"title":"ВОЗДЕЙСТВИЕ НА ЛЮДЕЙ","paragraphs":["Очевидцы сообщают о тревоге, нарушении чувства времени, ощущении чужого присутствия и желании уйти из освещённых мест. Некоторые слышат низкий гул, стук под землёй или повторяющиеся голоса.","Возможны кратковременная агрессия, бессонница, спутанность памяти и светочувствительность. Обычно симптомы исчезают после цикла, но рядом с точками выхода сохраняются несколько дней."]},{"title":"ИССЛЕДОВАНИЯ MIDGAS","paragraphs":["Институт наблюдает явление с конца XIX века. Ранние группы использовали журналы, механические сейсмографы и компасы; современные — дозиметры, тепловизоры, инфразвуковые микрофоны, сейсмические датчики и автоматические камеры.","Каждый цикл сравнивается с предыдущими по длительности резонанса, числу точек выхода, видам организмов и изменению поведения известных мутантов. Особое значение имеют синхронные измерения в Андреевке и удалённых контрольных точках."]},{"title":"ПРОТОКОЛ MIDGAS","paragraphs":["За 48 часов до прогноза группы переходят в полную готовность. Закрываются глубинные сектора, проверяются станции, готовятся биологические группы и непрерывный контроль магнитного поля, радиации и движения грунта.","Во время максимума самостоятельные выходы запрещены. Существ не преследуют без прямой угрозы: приоритет — фиксация маршрутов, отбор образцов и предотвращение проникновения в населённые районы."]},{"title":"ТЕКУЩИЙ СТАТУС","paragraphs":["Кроволунание остаётся активным и усиливается. Модели показывают рост амплитуды резонанса и числа подземных точек, реагирующих на полную Луну.","Если тенденция сохранится, отдельные эпизоды объединятся в продолжительный сезонный цикл. Тогда выход существ перестанет быть кратковременным событием и станет постоянной частью ночной среды в активных аномальных зонах."]}],"research":{"code":"KRVL-2017/2026","title":"КОЛИЧЕСТВЕННОЕ И ПОЛЕВОЕ ИССЛЕДОВАНИЕ КРОВОЛУНАНИЯ","period":"АРХИВ НАБЛЮДЕНИЙ 2017-2024 / МОДЕЛЬ РИСКА 2026","intro":"Раздел подготовлен по переданному сводному материалу «Исследование КРВЛ» и приведён к стандарту MIDGAS. В него включены матрица коэффициента вероятности кроволунания (КВК), календарь зарегистрированных дат, модели риска по дням недели и месяцам, оценки по цвету и фазе Луны, перечень полевых признаков, стадии явления и медицинские последствия. Исходный документ содержит внутренние расхождения, поэтому наблюдаемые события, расчётные вероятности и описательные гипотезы показаны раздельно.","methodology":[["Источник","Редактируемый PDF «Исследование КРВЛ», 3 страницы"],["Период датировок","17.07.2017-10.07.2024"],["Зарегистрировано событий","26, включая одну дату со служебной отметкой *"],["Базовый КВК","9,43% / критический по шкале исходного документа"],["Порог тревоги","Не менее 3 из 7 полевых признаков"],["Максимум матрицы","91% / 11-й период, четверг"],["Самый высокий месячный риск","Октябрь / 35%"],["Самый высокий недельный риск","Пятница / 18%"],["Стадия I","Три и более признака из контрольного перечня"],["Стадия II","Яркое кровавое окрашивание лунного диска"],["Стадия III","Красное небо и выраженная сырость у поверхности"],["Стадия IV","Измеримое изменение локальной гравитации"],["Стадия V","Выход неидентифицированных организмов из грунта"],["Ограничение","КВК является внутренней моделью MIDGAS и не относится к научной астрономической вероятности"]],"charts":[{"type":"heatmap","number":"01","title":"МАТРИЦА КОЭФФИЦИЕНТА ВЕРОЯТНОСТИ КРОВОЛУНАНИЯ","unit":"% КВК","note":"Двенадцать периодов исходной таблицы по дням недели. Нулём обозначены ячейки, помеченные в документе знаком X, то есть отсутствие расчётного значения, а не доказанная нулевая вероятность.","labels":["ПН","ВТ","СР","ЧТ","ПТ","СБ","ВС"],"metrics":[["СРЕДНЕЕ","9,43%"],["МАКСИМУМ","91%"],["КРИТИЧЕСКИХ ЯЧЕЕК","6"]],"analysis":["Матрица разрежена: из 84 возможных сочетаний числовые оценки даны только для 43. Поэтому среднее 9,43% нельзя интерпретировать как частоту события для любого произвольного дня; оно зависит от способа обращения с пропущенными значениями.","Наиболее выраженные выбросы приходятся на 7-й понедельник (58%), 9-й понедельник (38%), 10-ю среду (50%) и 11-й четверг (91%). Эти точки существенно выше основного массива и должны проверяться отдельно по исходным журналам.","Пятница и суббота представлены наиболее равномерно, но их значения в основном лежат ниже 10%. Высокий общий риск пятницы в сводной недельной модели формируется не только этой матрицей и, вероятно, включает дополнительные наблюдения."],"series":[{"name":"Период 01","shortName":"01","values":[0,0,0,0,5,2,2]},{"name":"Период 02","shortName":"02","values":[1,1,1,1,0,0,3]},{"name":"Период 03","shortName":"03","values":[3,0,0,0,0,3,0]},{"name":"Период 04","shortName":"04","values":[0,4,0,0,0,3,0]},{"name":"Период 05","shortName":"05","values":[0,9,0,0,9,4,1]},{"name":"Период 06","shortName":"06","values":[0,0,8,0,4,4,0]},{"name":"Период 07","shortName":"07","values":[58,0,0,0,2,3,9]},{"name":"Период 08","shortName":"08","values":[0,23,16,0,2,1,0]},{"name":"Период 09","shortName":"09","values":[38,0,0,0,0,4,0]},{"name":"Период 10","shortName":"10","values":[0,0,50,0,3,9,1]},{"name":"Период 11","shortName":"11","values":[2,12,0,91,3,0,2]},{"name":"Период 12","shortName":"12","values":[7,0,3,0,0,4,2]}]},{"type":"grouped-bar","number":"02","title":"СВОДНЫЙ РИСК ПО ДНЯМ НЕДЕЛИ","unit":"% КВК","note":"Воскресенье в источнике дано интервалом 2-9%, поэтому показаны нижняя и верхняя границы. Для остальных дней обе границы совпадают.","labels":["ПН","ВТ","СР","ЧТ","ПТ","СБ","ВС"],"threshold":17,"metrics":[["МАКСИМУМ","ПТ / 18%"],["МИНИМУМ","ЧТ / 0%"],["ДИАПАЗОН ВС","2-9%"]],"analysis":["Пятница единственная входит в IV уровень опасности по порогу 17% и выше. Понедельник и среда находятся в III и II диапазонах соответственно, тогда как четверг в исходной модели получил нулевое сводное значение.","Воскресный интервал слишком широк для точечного прогноза. В оперативной работе используется верхняя граница 9%, если одновременно выполняются три полевых признака или наблюдается сильный отлив."],"series":[{"name":"Нижняя оценка","values":[14,2,7,0,18,9,2]},{"name":"Верхняя оценка","values":[14,2,7,0,18,9,9]}]},{"type":"grouped-bar","number":"03","title":"МЕСЯЧНАЯ МОДЕЛЬ И ФАКТИЧЕСКОЕ РАСПРЕДЕЛЕНИЕ ДАТ","unit":"%","note":"Сравнение расчётного месячного КВК с долей 26 зарегистрированных событий 2017-2024 годов. Доли событий округлены до десятых.","labels":["ЯНВ","ФЕВ","МАР","АПР","МАЙ","ИЮН","ИЮЛ","АВГ","СЕН","ОКТ","НОЯ","ДЕК"],"threshold":17,"metrics":[["РИСК МОДЕЛИ","ОКТ / 35%"],["ПИК ДАТ","ИЮЛ / 34,6%"],["СОБЫТИЙ","26"]],"analysis":["Модель относит к IV уровню апрель, июль, октябрь и декабрь. Наблюдаемый календарь частично подтверждает июль и октябрь: на них приходится 9 и 6 событий соответственно.","Апрель имеет расчётный риск 19%, но в архиве отмечены только три события; декабрь при риске 22% также представлен тремя датами. Это указывает, что месячный КВК нельзя использовать без дневных и полевых признаков.","Февраль представлен одной датой 2024 года при модельном риске 8%. Январь, март, сентябрь и ноябрь не имеют зарегистрированных дат в переданном периоде, хотя модель не всегда присваивает им нулевой риск."],"series":[{"name":"Модель КВК","values":[14,8,2,19,15,7,24,6,1,35,4,22]},{"name":"Доля событий","values":[0,3.8,0,11.5,3.8,7.7,34.6,3.8,0,23.1,0,11.5]}]},{"type":"line","number":"04","title":"ДИНАМИКА ЗАРЕГИСТРИРОВАННЫХ СОБЫТИЙ","unit":"событий","note":"Годовое и накопленное число дат из реестра PDF. На 2025 и 2026 годы в источнике даты не внесены, поэтому они не включены в ряд.","labels":["2017","2018","2019","2020","2021","2022","2023","2024"],"metrics":[["ВСЕГО","26"],["ПИК","2023 / 6"],["2024","2 даты"]],"analysis":["Количество регистраций росло с одного события в год в 2017-2018 годах до шести в 2023 году. Снижение до двух дат в 2024 году нельзя считать завершением цикла: последняя дата отмечена звёздочкой, а полнота реестра после июля не подтверждена.","Накопленный ряд достигает 26 событий. Он отражает объём архива, а не истинную частоту явления: ранние годы могли быть недоучтены, а критерии регистрации после формирования кроволунанизма в 2020 году стали систематичнее."],"series":[{"name":"Новые регистрации","values":[1,1,3,4,5,4,6,2]},{"name":"Накопленный архив","values":[1,2,5,9,14,18,24,26]}]},{"type":"bar","number":"05","title":"ОЦЕНКА ПО ВИЗУАЛЬНОМУ ЦВЕТУ ЛУНЫ","unit":"% КВК","note":"Шесть последовательных визуальных категорий исходного документа, расположенных от нейтрального диска к максимально насыщенному красному. Названия категорий восстановлены редакционно, поскольку в PDF они представлены только цветовой шкалой.","labels":["НЕЙТР.","БЛЕДН.","ЖЁЛТ.","ОРАНЖ.","КРАСН.","ТЁМН.-КР."],"threshold":17,"metrics":[["МИНИМУМ","0%"],["КРАСНЫЙ","35%"],["ТЁМНО-КРАСНЫЙ","60%"]],"analysis":["Рост насыщенности в модели монотонно увеличивает вероятность от 0 до 60%. Переход в красный диапазон сразу переводит наблюдение в IV уровень опасности.","Цвет оценивается только по откалиброванной камере или визуально двумя наблюдателями. Облачность, городской свет, баланс белого и дым могут создавать ложное красное окрашивание."],"series":[{"name":"Оценка","values":[0,1,8,15,35,60]}]},{"type":"bar","number":"06","title":"ОЦЕНКА ПО ФАЗЕ ЛУНЫ","unit":"% КВК","note":"Четыре категории из исходной схемы: тонкий серп, половина диска, неполная и полная Луна. Фаза используется как вспомогательный, а не самостоятельный индикатор.","labels":["СЕРП","ПОЛОВИНА","НЕПОЛНАЯ","ПОЛНАЯ"],"threshold":17,"metrics":[["СЕРП","0%"],["НЕПОЛНАЯ","10%"],["ПОЛНАЯ","25%"]],"analysis":["Полная Луна получает 25% и соответствует IV уровню. Однако сама по себе она не запускает тревогу: по протоколу требуется совпадение как минимум трёх полевых признаков.","Фаза и цвет не должны суммироваться простым сложением. MIDGAS рассматривает их как зависимые наблюдения одного объекта и использует более высокую оценку с поправкой на наземные признаки."],"series":[{"name":"Оценка","values":[0,2,10,25]}]}],"sampleTable":{"title":"РЕЕСТР ДАТ И ПОЛЕВОЙ ПРОТОКОЛ","headers":["Год","Количество","Зарегистрированные даты","Редакционный статус"],"rows":[["2017","1","17.07","Ранний архив"],["2018","1","13.07","Ранний архив"],["2019","3","04.10 / 09.12 / 28.12","Подтверждённый ряд"],["2020","4","01.04 / 20.05 / 13.07 / 31.10","Начало систематического наблюдения"],["2021","5","03.04 / 22.06 / 22.07 / 12.10 / 24.12","Подтверждённый ряд"],["2022","4","01.04 / 01.07 / 14.07 / 17.10","Подтверждённый ряд"],["2023","6","13.06 / 10.07 / 15.07 / 24.08 / 10.10 / 31.10","Максимум регистраций"],["2024","2","12.02 / 10.07*","Вторая дата отмечена * в источнике"],["2025","0","Даты не внесены","Нет данных в PDF"],["2026","0","Даты не внесены","Нет данных в PDF"],["ПРИЗНАКИ","3 из 7","Соевые продукты на полу; белый поток транспорта; детёныш обзывает отца; 